import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface PlayerProfile {
  name: string;
  occupation: 'Farmer' | 'Shopkeeper' | 'Student' | 'Worker';
  monthlyIncome: number;
}

export interface Choice {
  id: string;
  text: string;
  description?: string;
}

export interface StatImpact {
  savings: number;
  debt: number;
  happiness: number;
}

export interface GameEvent {
  narrative: string;
  previousOutcome?: string; // What happened as a result of the LAST choice
  choices: Choice[];
  impact_on_stats?: StatImpact; // The immediate numerical impact of the PREVIOUS choice to apply
  isGameOver?: boolean;
}

export interface GameState {
  profile: PlayerProfile | null;
  savings: number;
  debt: number;
  happiness: number; // 0-100
  turn: number;
  history: string[]; // Keep track of the narrative for context
  currentEvent: GameEvent | null;
  isLoading: boolean;
  error: string | null;
  gameStatus: 'ONBOARDING' | 'PLAYING' | 'ENDED';
}

export const OCCUPATIONS = [
  { id: 'Farmer', label: 'Farmer (Kisan)', icon: '🌾', baseIncome: 15000, baseSavings: 20000 },
  { id: 'Shopkeeper', label: 'Shopkeeper (Dukandaar)', icon: '🏪', baseIncome: 20000, baseSavings: 50000 },
  { id: 'Worker', label: 'Daily Wage Worker', icon: '🔨', baseIncome: 12000, baseSavings: 5000 },
  { id: 'Student', label: 'Student', icon: '📚', baseIncome: 3000, baseSavings: 2000 },
] as const;

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { GameState, PlayerProfile } from "../types";

const apiKey = process.env.API_KEY;
// Using gemini-3-flash-preview as per guidance for text tasks
const MODEL_NAME = "gemini-3-flash-preview";

const ai = new GoogleGenAI({ apiKey: apiKey });

const SYSTEM_INSTRUCTION = `
You are "Arth Mitra", a trusted Indian financial guide. 
Your goal is NOT to teach theory, but to simulate life consequences.
You react to user decisions with realistic outcomes using simple language, Indian context, and emotional intelligence.

Core Rules:
1. No lectures. No definitions of financial terms unless explicitly asked.
2. No judgement or shaming.
3. Focus on habits and consequences (Cause -> Effect).
4. Short sentences. Everyday words.
5. Context: Rural or semi-urban India. Prices in Indian Rupees (₹).
6. Be calm, human, and grounded.

When generating a scenario:
- Create a realistic situation relevant to the user's occupation (e.g., crop failure for a farmer, festival sales for a shopkeeper, tuition fees for a student).
- Provide 2-3 distinct choices. One might be financially prudent but hard, one tempting but expensive, one neutral or risky.
- If this is a response to a previous choice, explain the outcome of that choice FIRST (e.g., "You bought the expensive bike. Your neighbors are impressed, but you used all your emergency cash.").

Data format:
Return JSON only.
`;

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    previousOutcome: {
      type: Type.STRING,
      description: "The immediate narrative result of the user's last action. Keep it under 2 sentences. Empty if first turn.",
    },
    narrative: {
      type: Type.STRING,
      description: "The new situation or challenge facing the user. Keep it engaging but concise (2-3 sentences).",
    },
    choices: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          text: { type: Type.STRING, description: "The action the user can take." },
          description: { type: Type.STRING, description: "A subtle hint about this choice (optional)." },
        },
        required: ["id", "text"],
      },
    },
    impact_on_stats: {
      type: Type.OBJECT,
      description: "The numerical change to apply to stats based on the LAST action taken. Use 0 if starting game.",
      properties: {
        savings: { type: Type.INTEGER, description: "Change in savings (e.g., -5000 or +2000)." },
        debt: { type: Type.INTEGER, description: "Change in debt (e.g., +10000 or -2000)." },
        happiness: { type: Type.INTEGER, description: "Change in happiness -10 to +10." },
      },
      required: ["savings", "debt", "happiness"],
    },
    isGameOver: {
      type: Type.BOOLEAN,
      description: "True if savings < -10000 (bankruptcy) or happiness <= 0 or turn > 10.",
    },
  },
  required: ["narrative", "choices", "impact_on_stats", "isGameOver"],
};

export const startSimulation = async (profile: PlayerProfile) => {
  const prompt = `
    Start a new simulation.
    Player Name: ${profile.name}
    Occupation: ${profile.occupation}
    Monthly Income: ₹${profile.monthlyIncome}

    Set the scene. Introduce Arth Mitra briefly and present the first life situation.
    Since this is the start, 'previousOutcome' should be empty and 'impact_on_stats' should be all 0.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Error starting simulation:", error);
    throw error;
  }
};

export const nextTurn = async (
  currentState: GameState,
  choiceId: string,
  choiceText: string
) => {
  const prompt = `
    Current Status:
    - Role: ${currentState.profile?.occupation}
    - Savings: ₹${currentState.savings}
    - Debt: ₹${currentState.debt}
    - Happiness: ${currentState.happiness}/100
    - Turn: ${currentState.turn}

    The player chose: "${choiceText}" (ID: ${choiceId}) in response to: "${currentState.currentEvent?.narrative}".

    1. Calculate the realistic financial and emotional impact of this choice.
    2. Generate the 'previousOutcome' describing the result of this choice.
    3. Generate the NEXT 'narrative' situation.
    4. Provide new choices.

    Remember:
    - If they spend money they don't have, Debt increases.
    - If they save, Happiness might drop slightly (sacrifice) or stay neutral, but Savings go up.
    - If Debt is high (> ₹50,000), the narrative should become stressful (creditors calling).
    - If Happiness is low, family health/relationships suffer.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Error generating next turn:", error);
    throw error;
  }
};

