import React, { useState } from 'react';
import { PlayerProfile, OCCUPATIONS } from '../types';
import { User, CheckCircle2 } from 'lucide-react';

interface OnboardingProps {
  onComplete: (profile: PlayerProfile) => void;
  isLoading: boolean;
}

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete, isLoading }) => {
  const [name, setName] = useState('');
  const [selectedOccupation, setSelectedOccupation] = useState<string | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (name && selectedOccupation) {
      const occ = OCCUPATIONS.find(o => o.id === selectedOccupation);
      if (occ) {
        onComplete({
          name,
          occupation: occ.id,
          monthlyIncome: occ.baseIncome,
        });
      }
    }
  };

  return (
    <div className="max-w-xl mx-auto p-6 space-y-8 animate-fade-in">
      <div className="text-center space-y-4">
        <div className="w-20 h-20 bg-earth-100 rounded-full flex items-center justify-center mx-auto mb-6">
          <User className="w-10 h-10 text-earth-600" />
        </div>
        <h2 className="text-3xl font-bold text-earth-900">Namaste!</h2>
        <p className="text-earth-600 text-lg leading-relaxed">
          I am Arth Mitra. I help people make sense of money, not with textbooks, but by walking through life together.
          <br/><br/>
          To begin, tell me a little about yourself.
        </p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-8">
        <div className="space-y-2">
          <label htmlFor="name" className="block text-sm font-medium text-earth-800 uppercase tracking-wider">
            What is your name?
          </label>
          <input
            type="text"
            id="name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="w-full p-4 text-lg border-2 border-earth-200 rounded-xl focus:border-earth-500 focus:ring-earth-500 outline-none transition-colors bg-white shadow-sm"
            placeholder="e.g. Rahul, Priya..."
            required
            disabled={isLoading}
          />
        </div>

        <div className="space-y-3">
          <span className="block text-sm font-medium text-earth-800 uppercase tracking-wider">
            What do you do?
          </span>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {OCCUPATIONS.map((occ) => (
              <button
                key={occ.id}
                type="button"
                onClick={() => setSelectedOccupation(occ.id)}
                disabled={isLoading}
                className={`
                  relative flex items-center p-4 rounded-xl border-2 transition-all duration-200 text-left
                  ${selectedOccupation === occ.id 
                    ? 'border-earth-600 bg-earth-50 text-earth-900 shadow-md transform scale-[1.02]' 
                    : 'border-earth-200 bg-white text-earth-600 hover:border-earth-300 hover:bg-earth-50'}
                `}
              >
                <span className="text-2xl mr-3">{occ.icon}</span>
                <div>
                  <div className="font-bold">{occ.label}</div>
                  <div className="text-xs opacity-75">~₹{occ.baseIncome.toLocaleString()}/mo</div>
                </div>
                {selectedOccupation === occ.id && (
                  <CheckCircle2 className="absolute top-3 right-3 w-5 h-5 text-earth-600" />
                )}
              </button>
            ))}
          </div>
        </div>

        <button
          type="submit"
          disabled={!name || !selectedOccupation || isLoading}
          className={`
            w-full py-4 rounded-xl text-white font-bold text-lg shadow-lg transition-all duration-300
            ${!name || !selectedOccupation || isLoading
              ? 'bg-gray-300 cursor-not-allowed' 
              : 'bg-earth-600 hover:bg-earth-700 hover:shadow-xl active:transform active:scale-95'}
          `}
        >
          {isLoading ? (
            <span className="flex items-center justify-center">
              <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Starting Life...
            </span>
          ) : (
            "Start My Journey"
          )}
        </button>
      </form>
    </div>
  );
};

import React from 'react';
import { GameState } from '../types';
import { IndianRupee, Heart, TrendingDown, TrendingUp } from 'lucide-react';

interface DashboardProps {
  state: GameState;
}

export const Dashboard: React.FC<DashboardProps> = ({ state }) => {
  // Helper for color coding stats
  const getSavingsColor = (amount: number) => {
    if (amount > 20000) return 'text-growth-700 bg-growth-50';
    if (amount > 5000) return 'text-earth-700 bg-earth-50';
    return 'text-debt-700 bg-debt-50';
  };

  const getHappinessColor = (val: number) => {
    if (val > 70) return 'text-growth-500';
    if (val > 40) return 'text-earth-500';
    return 'text-debt-500';
  };

  return (
    <div className="bg-white border-b border-earth-200 shadow-sm sticky top-[72px] z-40">
      <div className="max-w-3xl mx-auto px-4 py-3">
        <div className="grid grid-cols-3 gap-2 sm:gap-4 text-center">
          {/* Savings */}
          <div className={`rounded-lg p-2 flex flex-col items-center justify-center border border-earth-100 ${getSavingsColor(state.savings)} transition-colors duration-500`}>
            <div className="flex items-center space-x-1 text-sm opacity-80 mb-1 font-medium">
              <IndianRupee className="w-3 h-3" />
              <span>Savings</span>
            </div>
            <span className="font-bold text-lg sm:text-xl tracking-tight">
              ₹{state.savings.toLocaleString()}
            </span>
          </div>

          {/* Debt */}
          <div className={`rounded-lg p-2 flex flex-col items-center justify-center border border-earth-100 ${state.debt > 0 ? 'bg-debt-50 text-debt-700' : 'bg-earth-50 text-earth-600'} transition-colors duration-500`}>
            <div className="flex items-center space-x-1 text-sm opacity-80 mb-1 font-medium">
              {state.debt > 0 ? <TrendingDown className="w-3 h-3" /> : <TrendingUp className="w-3 h-3" />}
              <span>Debt</span>
            </div>
            <span className="font-bold text-lg sm:text-xl tracking-tight">
              ₹{state.debt.toLocaleString()}
            </span>
          </div>

          {/* Happiness */}
          <div className="rounded-lg p-2 flex flex-col items-center justify-center border border-earth-100 bg-white">
             <div className="flex items-center space-x-1 text-sm text-gray-500 mb-1 font-medium">
              <Heart className={`w-3 h-3 ${getHappinessColor(state.happiness)} fill-current`} />
              <span>Happiness</span>
            </div>
             <div className="w-full max-w-[80px] bg-gray-200 rounded-full h-2.5 mt-1 overflow-hidden">
                <div 
                  className={`h-2.5 rounded-full transition-all duration-700 ${state.happiness > 40 ? 'bg-growth-500' : 'bg-debt-500'}`} 
                  style={{ width: `${Math.max(5, state.happiness)}%` }}
                ></div>
              </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef } from 'react';
import { GameState, Choice, GameEvent } from '../types';
import { ArrowRight, AlertCircle, TrendingUp, TrendingDown, Heart } from 'lucide-react';

interface ScenarioViewProps {
  event: GameEvent;
  onMakeChoice: (choice: Choice) => void;
  isLoading: boolean;
  state: GameState;
}

export const ScenarioView: React.FC<ScenarioViewProps> = ({ event, onMakeChoice, isLoading, state }) => {
  const bottomRef = useRef<HTMLDivElement>(null);

  // Auto scroll to bottom when event changes to show new content
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [event]);

  // Stat impact badge component
  const ImpactBadge = ({ change, type }: { change: number, type: 'money' | 'heart' }) => {
    if (change === 0) return null;
    const isPositive = change > 0;
    const isGood = isPositive; // Generally

    // For debt, positive change is bad

    const colorClass = isGood ? 'text-growth-700 bg-growth-50' : 'text-debt-700 bg-debt-50';

    return (
      <span className={`inline-flex items-center px-2 py-0.5 rounded text-xs font-medium ${colorClass} ml-2`}>
        {isPositive ? '+' : ''}{change}
      </span>
    );
  };

  return (
    <div className="max-w-3xl mx-auto p-4 pb-24 space-y-6">

      {/* Previous Outcome Card (Feedback) */}
      {event.previousOutcome && (
        <div className="bg-earth-50 border-l-4 border-earth-500 p-4 rounded-r-lg animate-fade-in shadow-sm">
          <div className="flex items-start">
            <div className="flex-shrink-0 mt-0.5">
               <AlertCircle className="w-5 h-5 text-earth-600" />
            </div>
            <div className="ml-3">
              <p className="text-earth-900 font-medium text-lg leading-snug">
                {event.previousOutcome}
              </p>

              {/* Stat changes feedback */}
              {event.impact_on_stats && (
                <div className="flex flex-wrap gap-2 mt-3 text-sm">
                  {event.impact_on_stats.savings !== 0 && (
                     <span className={`flex items-center px-2 py-1 rounded-md border ${event.impact_on_stats.savings > 0 ? 'border-growth-200 bg-growth-50 text-growth-700' : 'border-debt-200 bg-debt-50 text-debt-700'}`}>
                        {event.impact_on_stats.savings > 0 ? <TrendingUp className="w-3 h-3 mr-1"/> : <TrendingDown className="w-3 h-3 mr-1"/>}
                        Savings {event.impact_on_stats.savings > 0 ? '+' : ''}{event.impact_on_stats.savings}
                     </span>
                  )}
                   {event.impact_on_stats.debt !== 0 && (
                     <span className={`flex items-center px-2 py-1 rounded-md border ${event.impact_on_stats.debt < 0 ? 'border-growth-200 bg-growth-50 text-growth-700' : 'border-debt-200 bg-debt-50 text-debt-700'}`}>
                        {event.impact_on_stats.debt > 0 ? <TrendingUp className="w-3 h-3 mr-1"/> : <TrendingDown className="w-3 h-3 mr-1"/>}
                        Debt {event.impact_on_stats.debt > 0 ? '+' : ''}{event.impact_on_stats.debt}
                     </span>
                  )}
                  {event.impact_on_stats.happiness !== 0 && (
                     <span className={`flex items-center px-2 py-1 rounded-md border ${event.impact_on_stats.happiness > 0 ? 'border-growth-200 bg-growth-50 text-growth-700' : 'border-debt-200 bg-debt-50 text-debt-700'}`}>
                        <Heart className="w-3 h-3 mr-1 fill-current"/>
                        {event.impact_on_stats.happiness > 0 ? '+' : ''}{event.impact_on_stats.happiness}
                     </span>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Current Narrative Card */}
      <div className="bg-white p-6 rounded-2xl shadow-lg border border-earth-100 animate-slide-up">
        <h3 className="text-sm font-bold text-earth-500 uppercase tracking-widest mb-2">
          Turn {state.turn} • {state.profile?.occupation}
        </h3>
        <p className="text-xl sm:text-2xl text-gray-800 leading-relaxed font-light">
          {event.narrative}
        </p>
      </div>

      {/* Choices Grid */}
      <div className="grid grid-cols-1 gap-4 pt-4">
        {event.choices.map((choice) => (
          <button
            key={choice.id}
            onClick={() => onMakeChoice(choice)}
            disabled={isLoading}
            className="group relative bg-white border-2 border-earth-200 hover:border-earth-500 hover:bg-earth-50 p-5 rounded-xl text-left transition-all duration-200 shadow-sm hover:shadow-md disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <div className="flex justify-between items-start">
              <div>
                <span className="block text-lg font-bold text-gray-900 group-hover:text-earth-900 mb-1">
                  {choice.text}
                </span>
                {choice.description && (
                  <span className="block text-sm text-gray-500 group-hover:text-earth-700">
                    {choice.description}
                  </span>
                )}
              </div>
              <ArrowRight className="w-5 h-5 text-earth-300 group-hover:text-earth-600 transform group-hover:translate-x-1 transition-transform mt-1" />
            </div>
          </button>
        ))}
      </div>

      {isLoading && (
        <div className="flex flex-col items-center justify-center py-8 space-y-3 animate-pulse">
           <div className="h-2 w-48 bg-earth-200 rounded"></div>
           <div className="text-earth-500 text-sm font-medium">Arth Mitra is thinking...</div>
        </div>
      )}

      <div ref={bottomRef} />
    </div>
  );
};

import React from 'react';
