  return (
    <div className="max-w-xl mx-auto p-8 text-center space-y-8 animate-fade-in pb-24">
      <div className={`w-24 h-24 rounded-full flex items-center justify-center mx-auto ${isWin ? 'bg-growth-100' : 'bg-debt-100'}`}>
        {isWin ? (
          <Trophy className="w-12 h-12 text-growth-600" />
        ) : (
          <AlertTriangle className="w-12 h-12 text-debt-600" />
        )}
      </div>

      <div className="space-y-4">
        <h2 className="text-3xl font-bold text-gray-900">
          {isWin ? "Journey Completed" : "Difficult Times"}
        </h2>
        <p className="text-lg text-gray-600 leading-relaxed">
          {isWin 
            ? "You have navigated the ups and downs of life with balance. Your family is secure, and you learned that money is a tool, not a master." 
            : "Life became overwhelming this time. Too much debt or too little happiness breaks the spirit. But life gives second chances."}
        </p>
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 grid grid-cols-3 gap-4">
        <div>
          <div className="text-xs text-gray-500 uppercase tracking-wide">Final Savings</div>
          <div className="text-xl font-bold text-gray-900">₹{state.savings.toLocaleString()}</div>
        </div>
        <div>
          <div className="text-xs text-gray-500 uppercase tracking-wide">Final Debt</div>
          <div className="text-xl font-bold text-gray-900">₹{state.debt.toLocaleString()}</div>
        </div>
        <div>
          <div className="text-xs text-gray-500 uppercase tracking-wide">Happiness</div>
          <div className="text-xl font-bold text-gray-900">{state.happiness}/100</div>
        </div>
      </div>

      <button
        onClick={onRestart}
        className="inline-flex items-center px-8 py-4 bg-earth-800 text-white rounded-xl font-bold text-lg hover:bg-earth-900 hover:shadow-lg transition-all transform hover:-translate-y-1"
      >
        <RefreshCcw className="w-5 h-5 mr-2" />
        Start New Life
      </button>
    </div>
  );
};

import React, { useState } from 'react';
import { Header } from './components/Header';
import { Onboarding } from './components/Onboarding';
import { Dashboard } from './components/Dashboard';
import { ScenarioView } from './components/ScenarioView';
import { GameOver } from './components/GameOver';
import { GameState, PlayerProfile, Choice, GameEvent, OCCUPATIONS } from './types';
import { startSimulation, nextTurn } from './services/geminiService';

// Default initial state
const initialState: GameState = {
  profile: null,
  savings: 0,
  debt: 0,
  happiness: 80,
  turn: 1,
  history: [],
  currentEvent: null,
  isLoading: false,
  error: null,
  gameStatus: 'ONBOARDING',
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(initialState);

  const handleStartGame = async (profile: PlayerProfile) => {
    setGameState(prev => ({ 
      ...prev, 
      profile, 
      isLoading: true,
      // Initialize savings based on occupation
      savings: OCCUPATIONS.find(o => o.id === profile.occupation)?.baseSavings || 5000
    }));

    try {
      const eventData = await startSimulation(profile);
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        gameStatus: 'PLAYING',
        currentEvent: eventData,
        history: [...prev.history, eventData.narrative]
      }));
    } catch (error) {
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        error: "Arth Mitra is having trouble connecting. Please try again."
      }));
    }
  };

  const handleChoice = async (choice: Choice) => {
    if (!gameState.currentEvent || !gameState.profile) return;

    setGameState(prev => ({ ...prev, isLoading: true, error: null }));

    try {
      const resultData = await nextTurn(gameState, choice.id, choice.text);

      const impacts = resultData.impact_on_stats;

      setGameState(prev => {
        const newSavings = prev.savings + impacts.savings;
        const newDebt = prev.debt + impacts.debt;
        let newHappiness = prev.happiness + impacts.happiness;
        // Cap happiness 0-100
        newHappiness = Math.min(100, Math.max(0, newHappiness));

        // Simple Game Over logic checks
        const isBankrupt = newSavings < -10000;
        const isDepressed = newHappiness <= 0;
        const isMaxTurns = prev.turn >= 10;
        const isGameOver = isBankrupt || isDepressed || isMaxTurns || resultData.isGameOver;

        return {
          ...prev,
          isLoading: false,
          savings: newSavings,
          debt: newDebt,
          happiness: newHappiness,
          turn: prev.turn + 1,
          currentEvent: resultData,
          history: [...prev.history, resultData.narrative],
          gameStatus: isGameOver ? 'ENDED' : 'PLAYING'
        };
      });

    } catch (error) {
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        error: "Connection lost. Arth Mitra is thinking..."
      }));
    }
  };

  const handleRestart = () => {
    setGameState(initialState);
  };

  return (
    <div className="min-h-screen bg-earth-50 text-earth-900 font-sans pb-10">
      <Header />

      <main className="container mx-auto max-w-4xl px-0 sm:px-4">
        {gameState.error && (
          <div className="p-4 mx-4 mt-4 bg-red-100 border border-red-300 text-red-800 rounded-lg">
            {gameState.error}
          </div>
        )}

        {gameState.gameStatus === 'ONBOARDING' && (
          <div className="mt-8">
            <Onboarding onComplete={handleStartGame} isLoading={gameState.isLoading} />
          </div>
        )}

        {gameState.gameStatus === 'PLAYING' && gameState.currentEvent && (
          <div className="animate-fade-in">
            <Dashboard state={gameState} />
            <div className="mt-6">
              <ScenarioView 
                event={gameState.currentEvent} 
                onMakeChoice={handleChoice} 
                isLoading={gameState.isLoading} 
                state={gameState}
              />
            </div>
          </div>
        )}

        {gameState.gameStatus === 'ENDED' && (
          <div className="mt-12">
             <GameOver state={gameState} onRestart={handleRestart} />
          </div>
        )}
      </main>
    </div>
  );
};

