import { GoogleGenAI, Type, Schema } from "@google/genai";
import { GameState, PlayerProfile } from "../types";

const apiKey = process.env.API_KEY;
// Using gemini-3-flash-preview as per guidance for text tasks
const MODEL_NAME = "gemini-3-flash-preview";

const ai = new GoogleGenAI({ apiKey: apiKey });

const SYSTEM_INSTRUCTION = `
You are "Arth Mitra", a trusted Indian financial guide. 
Your goal is NOT to teach theory, but to simulate life consequences.
You react to user decisions with realistic outcomes using simple language, Indian context, and emotional intelligence.

Core Rules:
1. No lectures. No definitions of financial terms unless explicitly asked.
2. No judgement or shaming.
3. Focus on habits and consequences (Cause -> Effect).
4. Short sentences. Everyday words.
5. Context: Rural or semi-urban India. Prices in Indian Rupees (₹).
6. Be calm, human, and grounded.

When generating a scenario:
- Create a realistic situation relevant to the user's occupation (e.g., crop failure for a farmer, festival sales for a shopkeeper, tuition fees for a student).
- Provide 2-3 distinct choices. One might be financially prudent but hard, one tempting but expensive, one neutral or risky.
- If this is a response to a previous choice, explain the outcome of that choice FIRST (e.g., "You bought the expensive bike. Your neighbors are impressed, but you used all your emergency cash.").

Data format:
Return JSON only.
`;

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    previousOutcome: {
      type: Type.STRING,
      description: "The immediate narrative result of the user's last action. Keep it under 2 sentences. Empty if first turn.",
    },
    narrative: {
      type: Type.STRING,
      description: "The new situation or challenge facing the user. Keep it engaging but concise (2-3 sentences).",
    },
    choices: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          text: { type: Type.STRING, description: "The action the user can take." },
          description: { type: Type.STRING, description: "A subtle hint about this choice (optional)." },
        },
        required: ["id", "text"],
      },
    },
    impact_on_stats: {
      type: Type.OBJECT,
      description: "The numerical change to apply to stats based on the LAST action taken. Use 0 if starting game.",
      properties: {
        savings: { type: Type.INTEGER, description: "Change in savings (e.g., -5000 or +2000)." },
        debt: { type: Type.INTEGER, description: "Change in debt (e.g., +10000 or -2000)." },
        happiness: { type: Type.INTEGER, description: "Change in happiness -10 to +10." },
        health: { type: Type.INTEGER, description: "Change in physical health -10 to +10." },
      },
      required: ["savings", "debt", "happiness", "health"],
    },
    isGameOver: {
      type: Type.BOOLEAN,
      description: "True if savings < -10000 (bankruptcy) or happiness <= 0 or health <= 0 or turn > 10.",
    },
  },
  required: ["narrative", "choices", "impact_on_stats", "isGameOver"],
};

export const startSimulation = async (profile: PlayerProfile) => {
  const prompt = `
    Start a new simulation.
    Player Name: ${profile.name}
    Occupation: ${profile.occupation}
    Monthly Income: ₹${profile.monthlyIncome}

    Set the scene. Introduce Arth Mitra briefly and present the first life situation.
    Since this is the start, 'previousOutcome' should be empty and 'impact_on_stats' should be all 0.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Error starting simulation:", error);
    throw error;
  }
};

export const nextTurn = async (
  currentState: GameState,
  choiceId: string,
  choiceText: string
) => {
  const prompt = `
    Current Status:
    - Role: ${currentState.profile?.occupation}
    - Savings: ₹${currentState.savings}
    - Debt: ₹${currentState.debt}
    - Happiness: ${currentState.happiness}/100
    - Health: ${currentState.health}/100
    - Turn: ${currentState.turn}

    The player chose: "${choiceText}" (ID: ${choiceId}) in response to: "${currentState.currentEvent?.narrative}".

    1. Calculate the realistic financial, emotional, and physical impact of this choice.
    2. Generate the 'previousOutcome' describing the result of this choice.
    3. Generate the NEXT 'narrative' situation.
    4. Provide new choices.

    Remember:
    - If they spend money they don't have, Debt increases.
    - If they save excessively by skipping meals/doctor, Health drops.
    - If they overwork, Health drops but Savings might rise.
    - If Debt is high (> ₹50,000), the narrative should become stressful (creditors calling).
    - If Happiness or Health is low, family/work suffers.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Error generating next turn:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { Header } from './components/Header';
import { Onboarding } from './components/Onboarding';
import { Dashboard } from './components/Dashboard';
import { ScenarioView } from './components/ScenarioView';
import { GameOver } from './components/GameOver';
import { GameState, PlayerProfile, Choice, GameEvent, OCCUPATIONS } from './types';
import { startSimulation, nextTurn } from './services/geminiService';

// Default initial state
const initialState: GameState = {
  profile: null,
  savings: 0,
  debt: 0,
  happiness: 80,
  health: 80,
  turn: 1,
  history: [],
  currentEvent: null,
  isLoading: false,
  error: null,
  gameStatus: 'ONBOARDING',
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(initialState);

  const handleStartGame = async (profile: PlayerProfile) => {
    setGameState(prev => ({ 
      ...prev, 
      profile, 
      isLoading: true,
      // Initialize savings based on occupation
      savings: OCCUPATIONS.find(o => o.id === profile.occupation)?.baseSavings || 5000
    }));

    try {
      const eventData = await startSimulation(profile);
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        gameStatus: 'PLAYING',
        currentEvent: eventData,
        history: [...prev.history, eventData.narrative]
      }));
    } catch (error) {
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        error: "Arth Mitra is having trouble connecting. Please try again."
      }));
    }
  };

  const handleChoice = async (choice: Choice) => {
    if (!gameState.currentEvent || !gameState.profile) return;

    setGameState(prev => ({ ...prev, isLoading: true, error: null }));

    try {
      const resultData = await nextTurn(gameState, choice.id, choice.text);

      const impacts = resultData.impact_on_stats;

      setGameState(prev => {
        const newSavings = prev.savings + impacts.savings;
        const newDebt = prev.debt + impacts.debt;
        let newHappiness = prev.happiness + impacts.happiness;
        let newHealth = prev.health + (impacts.health || 0);

        // Cap stats 0-100
        newHappiness = Math.min(100, Math.max(0, newHappiness));
        newHealth = Math.min(100, Math.max(0, newHealth));

        // Simple Game Over logic checks
        const isBankrupt = newSavings < -10000;
        const isDepressed = newHappiness <= 0;
        const isSick = newHealth <= 0;
        const isMaxTurns = prev.turn >= 10;
        const isGameOver = isBankrupt || isDepressed || isSick || isMaxTurns || resultData.isGameOver;

        return {
          ...prev,
          isLoading: false,
          savings: newSavings,
          debt: newDebt,
          happiness: newHappiness,
          health: newHealth,
          turn: prev.turn + 1,
          currentEvent: resultData,
          history: [...prev.history, resultData.narrative],
          gameStatus: isGameOver ? 'ENDED' : 'PLAYING'
        };
      });

    } catch (error) {
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        error: "Connection lost. Arth Mitra is thinking..."
      }));
    }
  };

  const handleRestart = () => {
    setGameState(initialState);
  };

  return (
    <div className="min-h-screen bg-earth-50 text-earth-900 font-sans pb-10">
      <Header />

      <main className="container mx-auto max-w-4xl px-0 sm:px-4">
        {gameState.error && (
          <div className="p-4 mx-4 mt-4 bg-red-100 border border-red-300 text-red-800 rounded-lg">
            {gameState.error}
          </div>
        )}

        {gameState.gameStatus === 'ONBOARDING' && (
          <div className="mt-8">
            <Onboarding onComplete={handleStartGame} isLoading={gameState.isLoading} />
          </div>
        )}

        {gameState.gameStatus === 'PLAYING' && gameState.currentEvent && (
          <div className="animate-fade-in">
            <Dashboard state={gameState} />
            <div className="mt-6">
              <ScenarioView 
                event={gameState.currentEvent} 
                onMakeChoice={handleChoice} 
                isLoading={gameState.isLoading} 
                state={gameState}
              />
            </div>
          </div>
        )}

        {gameState.gameStatus === 'ENDED' && (
          <div className="mt-12">
             <GameOver state={gameState} onRestart={handleRestart} />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

