    e.preventDefault();
    if (name && selectedOccupation) {
      const occ = OCCUPATIONS.find(o => o.id === selectedOccupation);
      if (occ) {
        onComplete({
          name,
          occupation: occ.id,
          monthlyIncome: occ.baseIncome,
        });
      }
    }
  };

  return (
    <div className="max-w-xl mx-auto p-4 sm:p-8 space-y-8 animate-fade-in glass-panel rounded-3xl shadow-glass border border-white/60">
