      <form onSubmit={handleSubmit} className="space-y-8">
        <div className="space-y-3">
          <label htmlFor="name" className="block text-sm font-bold text-earth-800 uppercase tracking-widest pl-1">
            What is your name?
          </label>
          <input
            type="text"
            id="name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="w-full p-4 text-xl border border-earth-200/60 rounded-xl focus:border-peach-400 focus:ring-4 focus:ring-peach-100 outline-none transition-all bg-white/70 backdrop-blur-sm shadow-inner placeholder-earth-300 text-earth-900"
