                  <div className="text-xs font-semibold opacity-70">~₹{occ.baseIncome.toLocaleString()}/mo</div>
                </div>
                {selectedOccupation === occ.id && (
                  <CheckCircle2 className="absolute top-3 right-3 w-5 h-5 text-peach-500" />
