import React, { useState, useEffect, useRef } from 'react';
import { GameState } from '../types';
import { getTranslation } from '../translations';
import { IndianRupee, Heart, Smile, TrendingDown, TrendingUp } from 'lucide-react';

interface DashboardProps {
  state: GameState;
}

const AnimatedCounter = ({ value, formatter }: { value: number, formatter?: (v: number) => string | number }) => {
  const [displayValue, setDisplayValue] = useState(value);
  const startTime = useRef<number>(0);
  const startValue = useRef<number>(value);
  const rafId = useRef<number | null>(null);

  useEffect(() => {
    startValue.current = displayValue;
    startTime.current = 0;

    // If value hasn't changed (initial render), we might not need to animate, 
    // but this effect runs on dependency [value]. 
    // If [value] is same as initial state, it's fine, startValue == value, loop finishes instantly.

    const animate = (timestamp: number) => {
      if (!startTime.current) startTime.current = timestamp;
      const progress = timestamp - startTime.current;
      const duration = 1500; // 1.5s for smooth transition

      if (progress < duration) {
        // easeOutExpo algorithm
        const ease = 1 - Math.pow(2, -10 * (progress / duration));
        const nextValue = startValue.current + (value - startValue.current) * ease;
        setDisplayValue(nextValue);
        rafId.current = requestAnimationFrame(animate);
      } else {
        setDisplayValue(value);
      }
    };

    rafId.current = requestAnimationFrame(animate);

    return () => {
      if (rafId.current) cancelAnimationFrame(rafId.current);
    };
  }, [value]);

  return <>{formatter ? formatter(displayValue) : Math.round(displayValue)}</>;
};

export const Dashboard: React.FC<DashboardProps> = ({ state }) => {
  const t = (key: any) => getTranslation(state.language, key);

  const savingsFormatter = (val: number) => {
    if (val > -1000 && val < 1000) return Math.round(val);
    return `${(val / 1000).toFixed(1)}k`;
  };

  const debtFormatter = (val: number) => {
    if (Math.round(val) <= 0) return '-';
    return `${(val / 1000).toFixed(1)}k`;
  };

  return (
    <div className="sticky top-[60px] z-40 my-6 px-4">
      <div className="flex justify-between gap-3 overflow-x-auto pb-2 scrollbar-hide snap-x">

        {/* Savings Bubble */}
        <div className="snap-start flex-1 min-w-[90px] bg-white/90 backdrop-blur-xl rounded-[2rem] p-4 border border-white shadow-glass shadow-mint-500/10 flex flex-col items-center justify-center relative overflow-hidden group hover:-translate-y-1 transition-transform duration-500">
