            <div className="w-8 h-8 rounded-full bg-mint-100 flex items-center justify-center mb-1 text-mint-600 shadow-sm">
                <IndianRupee className="w-4 h-4" strokeWidth={3} />
            </div>
            <span className="text-[10px] font-bold uppercase text-mint-700 tracking-wider mb-0.5">{t('savings')}</span>
            <span className="text-lg font-black text-earth-800 tracking-tight">
               <AnimatedCounter value={state.savings} formatter={savingsFormatter} />
            </span>
          </div>
        </div>

        {/* Debt Bubble */}
        <div className="snap-start flex-1 min-w-[90px] bg-white/90 backdrop-blur-xl rounded-[2rem] p-4 border border-white shadow-glass shadow-peach-500/10 flex flex-col items-center justify-center relative overflow-hidden group hover:-translate-y-1 transition-transform duration-500">
          <div className={`absolute inset-0 opacity-30 ${state.debt > 0 ? 'bg-gradient-to-b from-peach-100 to-transparent' : 'bg-gradient-to-b from-gray-50 to-transparent'}`}></div>
          <div className="relative z-10 flex flex-col items-center">
             <div className={`w-8 h-8 rounded-full flex items-center justify-center mb-1 shadow-sm ${state.debt > 0 ? 'bg-peach-100 text-peach-500' : 'bg-gray-100 text-gray-400'}`}>
                {state.debt > 0 ? <TrendingDown className="w-4 h-4" strokeWidth={3} /> : <TrendingUp className="w-4 h-4" strokeWidth={3} />}
            </div>
            <span className={`text-[10px] font-bold uppercase tracking-wider mb-0.5 ${state.debt > 0 ? 'text-peach-600' : 'text-gray-400'}`}>{t('debt')}</span>
            <span className={`text-lg font-black tracking-tight ${state.debt > 0 ? 'text-earth-800' : 'text-gray-400'}`}>
               <AnimatedCounter value={state.debt} formatter={debtFormatter} />
            </span>
          </div>
        </div>

        {/* Joy Bubble */}
        <div className="snap-start flex-1 min-w-[90px] bg-white/90 backdrop-blur-xl rounded-[2rem] p-4 border border-white shadow-glass shadow-yellow-500/10 flex flex-col items-center justify-center relative overflow-hidden group hover:-translate-y-1 transition-transform duration-500">
           <div className="absolute inset-0 bg-gradient-to-b from-yellow-50 to-transparent opacity-50"></div>
           <div className="relative z-10 flex flex-col items-center">
             <div className="w-8 h-8 rounded-full bg-yellow-100 flex items-center justify-center mb-1 text-yellow-500 shadow-sm">
                 <Smile className="w-5 h-5" strokeWidth={2.5} />
             </div>
             <span className="text-[10px] font-bold uppercase text-yellow-600 tracking-wider mb-0.5">{t('happiness')}</span>
             <span className="text-lg font-black text-earth-800">
               <AnimatedCounter value={state.happiness} />
             </span>
           </div>
        </div>

        {/* Health Bubble */}
        <div className="snap-start flex-1 min-w-[90px] bg-white/90 backdrop-blur-xl rounded-[2rem] p-4 border border-white shadow-glass shadow-pink-500/10 flex flex-col items-center justify-center relative overflow-hidden group hover:-translate-y-1 transition-transform duration-500">
           <div className="absolute inset-0 bg-gradient-to-b from-pink-50 to-transparent opacity-50"></div>
           <div className="relative z-10 flex flex-col items-center">
             <div className="w-8 h-8 rounded-full bg-pink-100 flex items-center justify-center mb-1 text-pink-500 shadow-sm">
                 <Heart className="w-4 h-4 fill-pink-500" />
             </div>
             <span className="text-[10px] font-bold uppercase text-pink-600 tracking-wider mb-0.5">{t('health')}</span>
             <span className="text-lg font-black text-earth-800">
               <AnimatedCounter value={state.health} />
             </span>
           </div>
        </div>

      </div>
    </div>
  );
};

