      <div className="flex gap-3 pb-2 w-max mx-auto sm:w-full sm:mx-0">

        {/* Savings Bubble */}
        <div className={`${statChipClass} group`}>
          <div className="flex items-center gap-1 mb-1 text-accent-green">
             <IndianRupee className="w-4 h-4" strokeWidth={2.5} />
          </div>
