import { GameEvent, Language } from '../types';
import { getTranslation } from '../translations';
import { TrendingUp, TrendingDown, Heart, Smile, ArrowRight, IndianRupee, Info } from 'lucide-react';
import { playSound } from '../services/audioService';

interface FeedbackViewProps {
  lastEvent: GameEvent;
  language: Language;
  onNext: () => void;
}

export const FeedbackView: React.FC<FeedbackViewProps> = ({ lastEvent, language, onNext }) => {
  const impacts = lastEvent.impact_on_stats;

  useEffect(() => {
    if (!impacts) return;

    // Play sound based on result
    const isBadOutcome = (impacts.debt > 500) || (impacts.happiness < -5) || (impacts.health < -5);
    const isGoodOutcome = (impacts.savings > 0) || (impacts.happiness > 5);

    if (isBadOutcome) {
      playSound('error');
    } else if (isGoodOutcome) {
      playSound('success');
    } else {
      playSound('click'); // Neutral
    }
  }, [lastEvent]); 

  if (!impacts) return null;

  const t = (key: any) => getTranslation(language, key);

  const handleNextClick = () => {
    playSound('click');
    onNext();
  };

  return (
    <div className="flex flex-col gap-6 animate-fade-in min-h-[50vh] justify-center">

      {/* Result Story Card */}
      <div className="glass-card p-6 rounded-card text-center">
        <div className="inline-block px-4 py-1.5 rounded-full bg-accent-yellow/20 text-brand text-caption font-bold tracking-wide uppercase mb-4">
          Result
        </div>
        <h2 className="text-h1 text-brand mb-3">
          {lastEvent.previous_outcome_title || "Done!"}
        </h2>
        <p className="text-body text-neutral-soft leading-relaxed mb-4">
          {lastEvent.previous_outcome_desc}
        </p>

        {/* Financial Flow Explanation */}
        {lastEvent.financial_explanation && (
           <div className="bg-white/50 border border-white rounded-xl p-3 text-caption text-neutral-dark flex items-start gap-2 text-left">
              <Info className="w-4 h-4 text-brand shrink-0 mt-0.5" />
              <span>{lastEvent.financial_explanation}</span>
           </div>
        )}
      </div>

      {/* Stat Changes Grid */}
      <div className="grid grid-cols-2 gap-4">

        {/* Savings Impact */}
        {impacts.savings !== 0 && (
          <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/60 ${impacts.savings > 0 ? 'border-accent-green' : 'border-accent-red'}`}>
            <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('savings')}</span>
            <div className={`text-h3 font-bold flex items-center ${impacts.savings > 0 ? 'text-accent-green' : 'text-accent-red'}`}>
              <IndianRupee className="w-4 h-4 mr-1" />
              {impacts.savings > 0 ? '+' : ''}{impacts.savings}
            </div>
          </div>
        )}

        {/* Happiness Impact */}
        {impacts.happiness !== 0 && (
          <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/60 ${impacts.happiness > 0 ? 'border-accent-yellow' : 'border-neutral-soft'}`}>
            <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('happiness')}</span>
             <div className={`text-h3 font-bold flex items-center ${impacts.happiness > 0 ? 'text-accent-yellow' : 'text-neutral-soft'}`}>
              <Smile className="w-5 h-5 mr-1" />
              {impacts.happiness > 0 ? '+' : ''}{impacts.happiness}%
            </div>
          </div>
        )}

         {/* Health Impact */}
         {impacts.health !== 0 && (
          <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/60 ${impacts.health > 0 ? 'border-accent-pink' : 'border-accent-red'}`}>
            <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('health')}</span>
             <div className={`text-h3 font-bold flex items-center ${impacts.health > 0 ? 'text-accent-pink' : 'text-accent-red'}`}>
              <Heart className="w-5 h-5 mr-1" />
              {impacts.health > 0 ? '+' : ''}{impacts.health}%
            </div>
          </div>
        )}

         {/* Debt Impact */}
         {impacts.debt !== 0 && (
          <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/60 ${impacts.debt < 0 ? 'border-accent-green' : 'border-accent-red'}`}>
            <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('debt')}</span>
             <div className={`text-h3 font-bold flex items-center ${impacts.debt < 0 ? 'text-accent-green' : 'text-accent-red'}`}>
              {impacts.debt > 0 ? <TrendingDown className="w-5 h-5 mr-1" /> : <TrendingUp className="w-5 h-5 mr-1" />}
              {impacts.debt > 0 ? '+' : ''}{impacts.debt}
            </div>
          </div>
        )}
      </div>

      {/* Primary CTA Button */}
      <button
        onClick={handleNextClick}
        className="w-full bg-brand text-white py-4 rounded-btn font-bold text-body shadow-btn hover:shadow-btn-hover hover:-translate-y-0.5 transition-all flex items-center justify-center group"
      >
        {t('next_turn')} <ArrowRight className="ml-2 w-5 h-5 group-hover:translate-x-1 transition-transform" />
      </button>

    </div>
  );
};

import React from 'react';
import { StatTransaction } from '../types';
import { X, IndianRupee, TrendingUp, Smile, Heart } from 'lucide-react';

interface StatHistoryProps {
  type: 'savings' | 'debt' | 'happiness' | 'health';
  history: StatTransaction[];
  onClose: () => void;
  title: string;
}

export const StatHistory: React.FC<StatHistoryProps> = ({ type, history, onClose, title }) => {
  // Filter history to only show transactions where the specific stat changed
  const filteredHistory = history.filter(t => t.changes[type] !== 0).reverse();

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center px-4">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-neutral-dark/40 backdrop-blur-sm animate-fade-in" 
        onClick={onClose}
      />

      {/* Modal Content */}
      <div className="bg-white rounded-[32px] w-full max-w-sm max-h-[70vh] flex flex-col shadow-2xl animate-fade-in relative z-10 overflow-hidden">

        {/* Header */}
        <div className="p-6 border-b border-neutral-100 flex items-center justify-between bg-neutral-50/50">
          <h3 className="text-h3 font-bold text-neutral-dark capitalize flex items-center gap-2">
            {type === 'savings' && <IndianRupee className="w-5 h-5 text-accent-green" />}
            {type === 'debt' && <TrendingUp className="w-5 h-5 text-accent-red" />}
            {type === 'happiness' && <Smile className="w-5 h-5 text-accent-yellow" />}
            {type === 'health' && <Heart className="w-5 h-5 text-accent-pink" />}
            {title} History
          </h3>
          <button 
            onClick={onClose}
            className="w-8 h-8 rounded-full bg-white border border-neutral-200 flex items-center justify-center text-neutral-soft hover:bg-neutral-100 transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* List */}
        <div className="overflow-y-auto p-4 flex flex-col gap-3">
          {filteredHistory.length === 0 ? (
            <div className="text-center py-8 text-neutral-soft text-caption">
              No history yet for this stat.
            </div>
          ) : (
            filteredHistory.map((item, index) => {
              const change = item.changes[type];
              const isPositive = change > 0;
              // For Debt, positive change is bad (Red), negative is good (Green)
              // For others, positive is good (Green), negative is bad (Red)

              let colorClass = "text-neutral-dark";
              if (type === 'debt') {
                colorClass = isPositive ? "text-accent-red" : "text-accent-green";
              } else {
                colorClass = isPositive ? "text-accent-green" : "text-accent-red";
              }

              return (
                <div key={index} className="flex items-center justify-between p-3 rounded-2xl bg-neutral-50 border border-neutral-100">
                  <div className="flex flex-col">
                    <span className="text-body font-bold text-neutral-dark leading-tight">{item.description}</span>
                    <span className="text-[10px] text-neutral-soft font-bold uppercase tracking-wider mt-0.5">Turn {item.turn}</span>
                  </div>
                  <div className={`text-h3 font-bold ${colorClass}`}>
                    {change > 0 ? '+' : ''}{change}{type === 'happiness' || type === 'health' ? '%' : ''}
                  </div>
                </div>
              );
            })
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GameState } from '../types';
import { getTranslation } from '../translations';
import { IndianRupee, Heart, Smile, TrendingDown, TrendingUp } from 'lucide-react';
import { StatHistory } from './StatHistory';
import { playSound } from '../services/audioService';

interface DashboardProps {
  state: GameState;
}

const AnimatedCounter = ({ value, formatter }: { value: number, formatter?: (v: number) => string | number }) => {
  const [displayValue, setDisplayValue] = useState(value);
  const startTime = useRef<number>(0);
  const startValue = useRef<number>(value);
  const rafId = useRef<number | null>(null);

  useEffect(() => {
    startValue.current = displayValue;
    startTime.current = 0;

    const animate = (timestamp: number) => {
      if (!startTime.current) startTime.current = timestamp;
      const progress = timestamp - startTime.current;
      const duration = 1500;

      if (progress < duration) {
        const ease = 1 - Math.pow(2, -10 * (progress / duration));
        const nextValue = startValue.current + (value - startValue.current) * ease;
        setDisplayValue(nextValue);
        rafId.current = requestAnimationFrame(animate);
      } else {
        setDisplayValue(value);
      }
    };

    rafId.current = requestAnimationFrame(animate);
    return () => { if (rafId.current) cancelAnimationFrame(rafId.current); };
  }, [value]);

  return <>{formatter ? formatter(displayValue) : Math.round(displayValue)}</>;
};

export const Dashboard: React.FC<DashboardProps> = ({ state }) => {
  const [selectedStat, setSelectedStat] = useState<'savings' | 'debt' | 'happiness' | 'health' | null>(null);

  const t = (key: any) => getTranslation(state.language, key);

  const savingsFormatter = (val: number) => {
    if (val > -1000 && val < 1000) return Math.round(val);
    return `${(val / 1000).toFixed(1)}k`;
  };

  const debtFormatter = (val: number) => {
    if (Math.round(val) <= 0) return '-';
    return `${(val / 1000).toFixed(1)}k`;
  };

  const percentageFormatter = (val: number) => {
    return `${Math.round(val)}%`;
  };

  const handleStatClick = (stat: 'savings' | 'debt' | 'happiness' | 'health') => {
    playSound('click');
    setSelectedStat(stat);
  };

  // Master UI Stat Chip Styles
  const statChipClass = "flex flex-col items-center justify-center p-3 rounded-chip min-w-[90px] min-h-[70px] bg-neutral-glass backdrop-blur-md border border-white/40 shadow-sm transition-transform active:scale-95 cursor-pointer hover:bg-white/60";

  return (
    <>
      <div className="sticky top-[68px] z-40 -mx-4 px-4 pt-2 pb-2 overflow-x-auto scrollbar-hide bg-gradient-to-b from-[#f0fdf9]/80 to-transparent backdrop-blur-sm">
        <div className="flex gap-3 w-max mx-auto sm:w-full sm:mx-0">

          {/* Savings Bubble */}
          <button onClick={() => handleStatClick('savings')} className={`${statChipClass} group`}>
            <div className="flex items-center gap-1 mb-1 text-accent-green">
               <IndianRupee className="w-4 h-4" strokeWidth={2.5} />
            </div>
            <span className="text-[10px] font-bold uppercase text-neutral-soft tracking-wider">{t('savings')}</span>
            <span className="text-h3 text-neutral-dark mt-0.5">
               <AnimatedCounter value={state.savings} formatter={savingsFormatter} />
            </span>
          </button>

          {/* Debt Bubble */}
          <button onClick={() => handleStatClick('debt')} className={`${statChipClass} group`}>
             <div className={`flex items-center gap-1 mb-1 ${state.debt > 0 ? 'text-accent-red' : 'text-neutral-soft'}`}>
               {state.debt > 0 ? <TrendingDown className="w-4 h-4" strokeWidth={2.5} /> : <TrendingUp className="w-4 h-4" strokeWidth={2.5} />}
             </div>
             <span className="text-[10px] font-bold uppercase text-neutral-soft tracking-wider">{t('debt')}</span>
             <span className="text-h3 text-neutral-dark mt-0.5">
                <AnimatedCounter value={state.debt} formatter={debtFormatter} />
             </span>
          </button>

          {/* Joy Bubble */}
          <button onClick={() => handleStatClick('happiness')} className={`${statChipClass} group`}>
             <div className="flex items-center gap-1 mb-1 text-accent-yellow">
                <Smile className="w-4 h-4" strokeWidth={2.5} />
             </div>
             <span className="text-[10px] font-bold uppercase text-neutral-soft tracking-wider">{t('happiness')}</span>
             <span className="text-h3 text-neutral-dark mt-0.5">
               <AnimatedCounter value={state.happiness} formatter={percentageFormatter} />
             </span>
          </button>

          {/* Health Bubble */}
          <button onClick={() => handleStatClick('health')} className={`${statChipClass} group`}>
             <div className="flex items-center gap-1 mb-1 text-accent-pink">
                <Heart className="w-4 h-4 fill-current" />
             </div>
             <span className="text-[10px] font-bold uppercase text-neutral-soft tracking-wider">{t('health')}</span>
             <span className="text-h3 text-neutral-dark mt-0.5">
               <AnimatedCounter value={state.health} formatter={percentageFormatter} />
             </span>
          </button>

        </div>
      </div>

      {selectedStat && (
        <StatHistory 
          type={selectedStat} 
          history={state.statHistory} 
          onClose={() => setSelectedStat(null)}
          title={t(selectedStat)}
        />
      )}
    </>
  );
};

import React, { useState } from 'react';
import { Header } from './components/Header';
import { Onboarding } from './components/Onboarding';
import { Dashboard } from './components/Dashboard';
import { ScenarioView } from './components/ScenarioView';
import { FeedbackView } from './components/FeedbackView';
import { GameOver } from './components/GameOver';
import { GameState, PlayerProfile, Choice, Language, OCCUPATIONS } from './types';
import { startSimulation, nextTurn } from './services/geminiService';

// Default initial state
const initialState: GameState = {
  profile: null,
  language: 'en',
  savings: 0,
  debt: 0,
  happiness: 80,
  health: 80,
  turn: 1,
  history: [],
  statHistory: [],
  currentEvent: null,
  lastEventData: null,
  isLoading: false,
  error: null,
  gameStatus: 'ONBOARDING',
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(initialState);

  const handleLanguageChange = (lang: Language) => {
    setGameState(prev => ({ ...prev, language: lang }));
  };

  const handleStartGame = async (profile: PlayerProfile) => {
    setGameState(prev => ({ 
      ...prev, 
      profile, 
      isLoading: true,
      // Initialize savings based on occupation
      savings: OCCUPATIONS.find(o => o.id === profile.occupation)?.baseSavings || 5000
    }));

    try {
      const eventData = await startSimulation(profile, gameState.language);
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        gameStatus: 'PLAYING',
        currentEvent: eventData,
        history: [...prev.history, eventData.narrative_hook]
      }));
    } catch (error) {
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        error: "Arth Mitra is having trouble connecting. Please try again."
      }));
    }
  };

  const handleChoice = async (choice: Choice) => {
    if (!gameState.currentEvent || !gameState.profile) return;

    setGameState(prev => ({ ...prev, isLoading: true, error: null }));

    try {
      // 1. Get AI Response (Impact + Next Turn)
      const resultData = await nextTurn(gameState, choice.id, choice.text, choice.cost_label);

      const impacts = resultData.impact_on_stats;

      // 2. Update Stats temporarily but hold off on showing next scenario
      // We show the Feedback view first using the data from resultData (previous_outcome_*)
      setGameState(prev => {
        // Safe cast to number to prevent string concatenation errors from AI response
        const impactSavings = Number(impacts.savings) || 0;
        const impactDebt = Number(impacts.debt) || 0;
        const impactHappiness = Number(impacts.happiness) || 0;
        const impactHealth = Number(impacts.health) || 0;

        let newSavings = prev.savings + impactSavings;
        let newDebt = prev.debt + impactDebt;

        // Smart Balance Normalization
        // If savings go negative, transfer to debt
        if (newSavings < 0) {
          newDebt += Math.abs(newSavings);
          newSavings = 0;
        }

        // If debt goes negative (overpayment), transfer to savings
        if (newDebt < 0) {
          newSavings += Math.abs(newDebt);
          newDebt = 0;
        }

        let newHappiness = prev.happiness + impactHappiness;
        let newHealth = prev.health + impactHealth;

        // Cap stats 0-100
        newHappiness = Math.min(100, Math.max(0, newHappiness));
        newHealth = Math.min(100, Math.max(0, newHealth));

        // 3. Record the transaction history (calculate ACTUAL changes)
        const actualChangeSavings = newSavings - prev.savings;
        const actualChangeDebt = newDebt - prev.debt;
        const actualChangeHappiness = newHappiness - prev.happiness;
        const actualChangeHealth = newHealth - prev.health;

        const newTransaction = {
          turn: prev.turn,
          description: choice.text, // Use the user's choice as the history description
          changes: {
            savings: actualChangeSavings,
            debt: actualChangeDebt,
            happiness: actualChangeHappiness,
            health: actualChangeHealth
          }
        };

        return {
          ...prev,
          isLoading: false,
          savings: newSavings,
          debt: newDebt,
          happiness: newHappiness,
          health: newHealth,
          turn: prev.turn + 1,

          statHistory: [...prev.statHistory, newTransaction],

          // Store the FULL result data to show in Feedback view
          lastEventData: resultData, 
          // Don't update currentEvent yet (narrative hook), wait for user to click Next
          currentEvent: resultData, 

          gameStatus: 'FEEDBACK' // Switch to Feedback mode
        };
      });

    } catch (error) {
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        error: "Connection lost. Arth Mitra is thinking..."
      }));
    }
  };

  const handleNextTurn = () => {
    setGameState(prev => {
       // Game Over Conditions
       const isDepressed = prev.happiness <= 0;
       const isSick = prev.health <= 0;
       const isHighDebt = prev.debt > 50000; // Financial ruin threshold
       const isMaxTurns = prev.turn >= 12;

       // Check if any critical failure state is met or game ends naturally
       const isGameOver = isDepressed || isSick || isHighDebt || isMaxTurns || prev.lastEventData?.isGameOver;

       return {
         ...prev,
         gameStatus: isGameOver ? 'ENDED' : 'PLAYING'
       };
    });
  };

  const handleRestart = () => {
    setGameState(initialState);
  };

  return (
    <div className="min-h-screen text-neutral-dark font-sans flex flex-col bg-fixed">
      <Header language={gameState.language} onLanguageChange={handleLanguageChange} />

      {/* Main Container - Natural Flow, No Overlaps */}
      <main className="flex-1 w-full max-w-[500px] mx-auto px-4 py-6 flex flex-col gap-6 relative z-0">

        {gameState.error && (
          <div className="p-4 bg-accent-red/10 border border-accent-red/20 text-accent-red rounded-card backdrop-blur-sm animate-fade-in text-caption">
            {gameState.error}
          </div>
        )}

        {gameState.gameStatus === 'ONBOARDING' && (
          <Onboarding 
            onComplete={handleStartGame} 
            isLoading={gameState.isLoading} 
            language={gameState.language}
            setLanguage={handleLanguageChange}
          />
        )}

        {/* Game Loop Container */}
        {(gameState.gameStatus === 'PLAYING' || gameState.gameStatus === 'FEEDBACK') && gameState.currentEvent && (
          <div className="flex flex-col gap-6 w-full animate-fade-in">
            <Dashboard state={gameState} />

            <div className="flex flex-col gap-6 w-full">
              {gameState.gameStatus === 'PLAYING' ? (
                <ScenarioView 
                  event={gameState.currentEvent} 
                  onMakeChoice={handleChoice} 
                  isLoading={gameState.isLoading} 
                  state={gameState}
                />
              ) : (
                gameState.lastEventData && (
                  <FeedbackView 
                    lastEvent={gameState.lastEventData}
                    language={gameState.language}
                    onNext={handleNextTurn}
                  />
                )
              )}
            </div>
          </div>
        )}

        {gameState.gameStatus === 'ENDED' && (
          <GameOver state={gameState} onRestart={handleRestart} />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect } from 'react';
import { GameEvent, Language } from '../types';
import { getTranslation } from '../translations';
import { TrendingUp, TrendingDown, Heart, Smile, ArrowRight, IndianRupee, Info } from 'lucide-react';
import { playSound } from '../services/audioService';

interface FeedbackViewProps {
  lastEvent: GameEvent;
  language: Language;
  onNext: () => void;
}

export const FeedbackView: React.FC<FeedbackViewProps> = ({ lastEvent, language, onNext }) => {
  const impacts = lastEvent.impact_on_stats;

  useEffect(() => {
    if (!impacts) return;

    // Play sound based on result
    const isBadOutcome = (impacts.debt > 500) || (impacts.happiness < -5) || (impacts.health < -5);
    const isGoodOutcome = (impacts.savings > 0) || (impacts.happiness > 5);

    if (isBadOutcome) {
      playSound('error');
    } else if (isGoodOutcome) {
      playSound('success');
    } else {
      playSound('click'); // Neutral
    }
  }, [lastEvent]); 

  if (!impacts) return null;

  const t = (key: any) => getTranslation(language, key);

  const handleNextClick = () => {
    playSound('click');
    onNext();
  };

  return (
    <div className="flex flex-col gap-6 animate-fade-in min-h-[50vh] justify-center">

      {/* Result Story Card */}
      <div className="glass-card p-6 rounded-card text-center">
        <div className="inline-block px-4 py-1.5 rounded-full bg-accent-yellow/20 text-brand text-caption font-bold tracking-wide uppercase mb-4">
          Result
        </div>
        <h2 className="text-h1 text-brand mb-3">
          {lastEvent.previous_outcome_title || "Done!"}
        </h2>
        <p className="text-body text-neutral-soft leading-relaxed mb-4">
          {lastEvent.previous_outcome_desc}
        </p>

        {/* Financial Flow Explanation */}
        {lastEvent.financial_explanation && (
           <div className="bg-white/50 border border-white rounded-xl p-3 text-caption text-neutral-dark flex items-start gap-2 text-left">
              <Info className="w-4 h-4 text-brand shrink-0 mt-0.5" />
              <span>{lastEvent.financial_explanation}</span>
           </div>
        )}
      </div>

      {/* Stat Changes Grid */}
      <div className="grid grid-cols-2 gap-4">

        {/* Savings Impact */}
        {impacts.savings !== 0 && (
          <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/60 ${impacts.savings > 0 ? 'border-accent-green' : 'border-accent-red'}`}>
            <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('savings')}</span>
            <div className={`text-h3 font-bold flex items-center ${impacts.savings > 0 ? 'text-accent-green' : 'text-accent-red'}`}>
              <IndianRupee className="w-4 h-4 mr-1" />
              {impacts.savings > 0 ? '+' : ''}{impacts.savings}
            </div>
          </div>
        )}

        {/* Happiness Impact */}
        {impacts.happiness !== 0 && (
          <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/60 ${impacts.happiness > 0 ? 'border-accent-yellow' : 'border-neutral-soft'}`}>
            <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('happiness')}</span>
             <div className={`text-h3 font-bold flex items-center ${impacts.happiness > 0 ? 'text-accent-yellow' : 'text-neutral-soft'}`}>
              <Smile className="w-5 h-5 mr-1" />
              {impacts.happiness > 0 ? '+' : ''}{impacts.happiness}%
            </div>
          </div>
        )}

         {/* Health Impact */}
         {impacts.health !== 0 && (
          <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/60 ${impacts.health > 0 ? 'border-accent-pink' : 'border-accent-red'}`}>
            <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('health')}</span>
             <div className={`text-h3 font-bold flex items-center ${impacts.health > 0 ? 'text-accent-pink' : 'text-accent-red'}`}>
              <Heart className="w-5 h-5 mr-1" />
              {impacts.health > 0 ? '+' : ''}{impacts.health}%
            </div>
          </div>
        )}

         {/* Debt Impact */}
         {impacts.debt !== 0 && (
          <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/60 ${impacts.debt < 0 ? 'border-accent-green' : 'border-accent-red'}`}>
            <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('debt')}</span>
             <div className={`text-h3 font-bold flex items-center ${impacts.debt < 0 ? 'text-accent-green' : 'text-accent-red'}`}>
              {/* Debt > 0 means Debt Increased (Bad, Red, TrendingUp). Debt < 0 means Debt Decreased (Good, Green, TrendingDown) */}
              {impacts.debt > 0 ? <TrendingUp className="w-5 h-5 mr-1" /> : <TrendingDown className="w-5 h-5 mr-1" />}
              {impacts.debt > 0 ? '+' : ''}{impacts.debt}
            </div>
          </div>
        )}
      </div>

      {/* Primary CTA Button */}
      <button
        onClick={handleNextClick}
        className="w-full bg-brand text-white py-4 rounded-btn font-bold text-body shadow-btn hover:shadow-btn-hover hover:-translate-y-0.5 transition-all flex items-center justify-center group"
      >
        {t('next_turn')} <ArrowRight className="ml-2 w-5 h-5 group-hover:translate-x-1 transition-transform" />
      </button>

    </div>
  );
};

import React, { useEffect } from 'react';
