const getContextualTip = (state: GameState): string => {
  const { debt, health, savings, profile, language } = state;

  let tipKey: keyof typeof TIP_DATABASE = 'default';

  // Priority 1: Critical Stats
  if (debt > 25000) {
    tipKey = 'high_debt';
  } else if (health < 40) {
    tipKey = 'low_health';
  } else if (savings < 2000) {
    tipKey = 'low_savings';
  } 
  // Priority 2: Role Specific
  else if (profile?.occupation && TIP_DATABASE[profile.occupation as keyof typeof TIP_DATABASE]) {
    tipKey = profile.occupation as keyof typeof TIP_DATABASE;
  }

  const tipObj = TIP_DATABASE[tipKey] || TIP_DATABASE['default'];
  return tipObj[language] || tipObj['en'];
};


// --- MAIN APP COMPONENT ---

// Default initial state
const initialState: GameState = {
  profile: null,
  language: 'en',
  savings: 0,
  debt: 0,
  happiness: 80,
  health: 80,
  turn: 1,
  history: [],
  statHistory: [],
  currentEvent: null,
  lastEventData: null,
  isLoading: false,
  error: null,
  gameStatus: 'ONBOARDING',
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(initialState);

  const handleLanguageChange = (lang: Language) => {
    setGameState(prev => ({ ...prev, language: lang }));
  };

  const handleStartGame = async (profile: PlayerProfile) => {
    setGameState(prev => ({ 
      ...prev, 
      profile, 
      isLoading: true,
      // Initialize savings based on occupation
      savings: OCCUPATIONS.find(o => o.id === profile.occupation)?.baseSavings || 5000
    }));

    try {
      const eventData = await startSimulation(profile, gameState.language);
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        gameStatus: 'PLAYING',
        currentEvent: eventData,
        history: [...prev.history, eventData.narrative_hook]
      }));
    } catch (error) {
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        error: "Arth Mitra is having trouble connecting. Please try again."
      }));
    }
  };

  const handleChoice = async (choice: Choice) => {
    if (!gameState.currentEvent || !gameState.profile) return;

    setGameState(prev => ({ ...prev, isLoading: true, error: null }));

    try {
      // 1. Get AI Response (Impact + Next Turn)
      const resultData = await nextTurn(gameState, choice.id, choice.text, choice.cost_label);

      const impacts = resultData.impact_on_stats;

      // 2. Update Stats with Safe Parsing
      setGameState(prev => {
        const impactSavings = safeParseInt(impacts.savings);
        const impactDebt = safeParseInt(impacts.debt);
        const impactHappiness = safeParseInt(impacts.happiness);
        const impactHealth = safeParseInt(impacts.health);

        let newSavings = prev.savings + impactSavings;
        let newDebt = prev.debt + impactDebt;

        // Smart Balance Normalization
        // If savings go negative, debt increases.
        if (newSavings < 0) {
          newDebt += Math.abs(newSavings);
          newSavings = 0;
        }

        // If debt goes negative (overpaid), it flows back to savings.
        if (newDebt < 0) {
          newSavings += Math.abs(newDebt);
          newDebt = 0;
        }

        let newHappiness = prev.happiness + impactHappiness;
        let newHealth = prev.health + impactHealth;

        newHappiness = Math.min(100, Math.max(0, newHappiness));
        newHealth = Math.min(100, Math.max(0, newHealth));

        // 3. Record history (Actual delta after normalization)
        const actualChangeSavings = newSavings - prev.savings;
        const actualChangeDebt = newDebt - prev.debt;
        const actualChangeHappiness = newHappiness - prev.happiness;
        const actualChangeHealth = newHealth - prev.health;

        const newTransaction = {
          turn: prev.turn,
          description: choice.text,
          changes: {
            savings: actualChangeSavings,
            debt: actualChangeDebt,
            happiness: actualChangeHappiness,
            health: actualChangeHealth
          }
        };

        return {
          ...prev,
          isLoading: false,
          savings: newSavings,
          debt: newDebt,
          happiness: newHappiness,
          health: newHealth,
          turn: prev.turn + 1,
          statHistory: [...prev.statHistory, newTransaction],
          lastEventData: resultData, 
          currentEvent: resultData, 
          gameStatus: 'FEEDBACK'
        };
      });

    } catch (error) {
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        error: "Connection lost. Arth Mitra is thinking..."
      }));
    }
  };

  const handleNextTurn = () => {
    setGameState(prev => {
       const isDepressed = prev.happiness <= 0;
       const isSick = prev.health <= 0;
       const isHighDebt = prev.debt > 50000;
       const isMaxTurns = prev.turn >= 12;

       const isGameOver = isDepressed || isSick || isHighDebt || isMaxTurns || prev.lastEventData?.isGameOver;

       return {
         ...prev,
         gameStatus: isGameOver ? 'ENDED' : 'PLAYING'
       };
    });
  };

  const handleRestart = () => {
    setGameState(initialState);
  };

  // Get current tip based on state
  const currentTip = useMemo(() => getContextualTip(gameState), [
    gameState.debt, 
    gameState.health, 
    gameState.savings, 
    gameState.profile?.occupation, 
    gameState.language,
    gameState.turn // Update tip every turn
  ]);

  return (
    // Outer Layout: Full height, flex column, hidden overflow
    <div className="h-full w-full flex flex-col bg-[#f0fdf9] text-neutral-dark font-sans overflow-hidden relative">

      {/* Background Gradient Layer */}
      <div className="absolute inset-0 z-0 bg-gradient-to-br from-[#f0fdf9] to-[#fff5f2] pointer-events-none" />

      {/* Header: Static, safe from overlap */}
      <div className="relative z-50 flex-none border-b border-white/20 shadow-sm bg-white/40 backdrop-blur-md">
        <Header language={gameState.language} onLanguageChange={handleLanguageChange} />
      </div>

      {/* Scrollable Main Area: Content pushes naturally */}
      <main className="relative z-0 flex-1 overflow-y-auto overflow-x-hidden w-full scroll-smooth">
        <div className="w-full max-w-[500px] mx-auto px-4 pb-12 flex flex-col min-h-full">

          {/* Error Banner */}
          {gameState.error && (
            <div className="mt-4 p-4 bg-accent-red/10 border border-accent-red/20 text-accent-red rounded-card animate-fade-in text-caption">
              {gameState.error}
            </div>
          )}

          {/* Onboarding */}
          {gameState.gameStatus === 'ONBOARDING' && (
            <div className="flex-1 flex flex-col justify-center py-6">
              <Onboarding 
                onComplete={handleStartGame} 
                isLoading={gameState.isLoading} 
                language={gameState.language}
                setLanguage={handleLanguageChange}
              />
            </div>
          )}

          {/* Game Loop */}
          {(gameState.gameStatus === 'PLAYING' || gameState.gameStatus === 'FEEDBACK') && gameState.currentEvent && (
            <div className="flex flex-col w-full animate-fade-in">

              {/* Sticky Dashboard inside scroll area */}
              {/* Stacks naturally below Header visually, but sticks to top of scroll area */}
              <Dashboard state={gameState} />

              {/* Vertical spacing after dashboard */}
              <div className="h-6 shrink-0" /> 

              {/* Dynamic Content Area */}
              <div className="flex flex-col gap-6 w-full">
                {gameState.gameStatus === 'PLAYING' ? (
                  <ScenarioView 
                    event={gameState.currentEvent} 
                    onMakeChoice={handleChoice} 
                    isLoading={gameState.isLoading} 
                    state={gameState}
                  />
                ) : (
                  gameState.lastEventData && (
                    <FeedbackView 
                      lastEvent={gameState.lastEventData}
                      language={gameState.language}
                      onNext={handleNextTurn}
                    />
                  )
                )}

                {/* Contextual Financial Tip Section */}
                <div className="mx-1 mt-2 mb-6 p-4 bg-brand/5 border border-brand/10 rounded-2xl flex gap-3 items-start animate-fade-in shadow-sm">
                   <div className="p-2 bg-brand/10 rounded-full shrink-0 text-brand mt-0.5">
                      <Lightbulb size={18} strokeWidth={2.5} />
                   </div>
                   <div className="flex-1">
                      <h4 className="text-caption font-bold text-brand uppercase tracking-wider mb-1 opacity-90">
                        {gameState.language === 'en' ? 'Arth Mitra Says' : 'अर्थ मित्र की सलाह'}
                      </h4>
                      <p className="text-body text-neutral-soft/90 italic leading-relaxed">"{currentTip}"</p>
                   </div>
                </div>

              </div>
            </div>
          )}

          {/* Game Over */}
          {gameState.gameStatus === 'ENDED' && (
             <div className="flex-1 flex flex-col justify-center py-6">
              <GameOver state={gameState} onRestart={handleRestart} />
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { GameState, PlayerProfile, Language } from "../types";

const apiKey = process.env.API_KEY;
const MODEL_NAME = "gemini-3-flash-preview";

const ai = new GoogleGenAI({ apiKey: apiKey });

// Helper to get language context for the AI
const getLangContext = (lang: Language) => {
  switch (lang) {
    case 'hi': return "Response Language: HINDI (Devanagari script). Use simple, everyday Hindi.";
    case 'hinglish': return "Response Language: HINGLISH (Latin script). Use the way Indian millennials chat. Casual, friendly.";
    default: return "Response Language: ENGLISH. Simple, accessible, Indian context.";
  }
};

const SYSTEM_INSTRUCTION = `
You are "Arth Mitra", a friendly Indian financial buddy.
Your goal: Simulate financial consequences with DOPAMINE hits and EMOTIONAL decisions.

STYLE RULES:
1. **NO Paragraphs.** Use punchy, 1-line hooks.
2. **Context:** Rural/Semi-urban India.
3. **Tone:** Warm, non-judgmental, casual (like a friend).
4. **Format:** Strict JSON.

FINANCIAL RULES (STRICT):
1. **Cost Consistency:** If a choice costs money (e.g. ₹500), you MUST output a negative savings impact (e.g. -500).
2. **Debt Reality:** If the player has existing Debt, assume they pay ~2% interest per turn unless they pay it off. Increase the debt impact slightly (e.g. debt: +500) to simulate this if no payment is made.
3. **Income:** Do NOT automatically add monthly income unless the narrative specifically says "It is Payday".
`;

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    // Feedback for the PREVIOUS action
    previous_outcome_title: {
      type: Type.STRING,
      description: "Short celebratory or sympathetic title about the LAST choice (e.g., 'Smart Move!' or 'Ouch!'). Max 4 words.",
    },
    previous_outcome_desc: {
      type: Type.STRING,
      description: "1-sentence explanation of the result. (e.g., 'Mom is happy, but your pockets are empty.')",
    },
    financial_explanation: {
      type: Type.STRING,
      description: "One strict sentence explaining money flow. Format: '[Amount] [Source] -> [Destination]'. Example: '₹5000 from Savings paid for School Fees' or '₹2000 Bonus added to Savings'.",
    },
    impact_on_stats: {
      type: Type.OBJECT,
      properties: {
        savings: { type: Type.INTEGER },
        debt: { type: Type.INTEGER },
        happiness: { type: Type.INTEGER },
        health: { type: Type.INTEGER },
      },
      required: ["savings", "debt", "happiness", "health"],
    },

    // The NEXT Situation
    narrative_hook: {
      type: Type.STRING,
      description: "The new situation in ONE punchy line. (e.g., 'Family wedding next week. Wallet is tight.')",
    },
    choices: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          text: { type: Type.STRING, description: "Action text (e.g. 'Buy Gold Gift')" },
          emoji: { type: Type.STRING, description: "Single emoji representing this action" },
          cost_label: { type: Type.STRING, description: "Cost display (e.g. '₹8000' or 'Free')" },
          tag: { type: Type.STRING, description: "Short emotional/financial summary (e.g. 'Loved | Wallet Empty')" },
          type: { type: Type.STRING, enum: ['expensive', 'balanced', 'cheap'] },
        },
        required: ["id", "text", "emoji", "cost_label", "tag", "type"],
      },
    },
    isGameOver: { type: Type.BOOLEAN },
  },
  required: ["narrative_hook", "choices", "impact_on_stats", "isGameOver", "financial_explanation"],
};

export const startSimulation = async (profile: PlayerProfile, lang: Language) => {
  const langInstruction = getLangContext(lang);

  const prompt = `
    START NEW GAME.
    Player: ${profile.name}, Role: ${profile.occupation}, Income: ₹${profile.monthlyIncome}.
    ${langInstruction}

    1. Introduce the first situation (narrative_hook).
    2. Provide 3 choices.
    3. Since it's the start, 'previous_outcome_title', 'previous_outcome_desc', 'financial_explanation' should be empty string, and 'impact_on_stats' values should be 0.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Error starting simulation:", error);
    throw error;
  }
};

export const nextTurn = async (
  currentState: GameState,
  choiceId: string,
  choiceText: string,
  choiceCostLabel?: string
) => {
  const langInstruction = getLangContext(currentState.language);

  const prompt = `
    ${langInstruction}
    Current Status:
    - Role: ${currentState.profile?.occupation}
    - Savings: ₹${currentState.savings}
    - Debt: ₹${currentState.debt}
    - Happiness: ${currentState.happiness}
    - Health: ${currentState.health}
    - Turn: ${currentState.turn}

    Player Action: "${choiceText}" (Cost/Label: ${choiceCostLabel || 'N/A'}).
    Previous Scenario: "${currentState.currentEvent?.narrative_hook}".

    1. Calculate IMPACT of this action (Feedback). 
       IMPORTANT: If the action had a cost (e.g. ₹500), you MUST SUBTRACT that amount from 'savings' in 'impact_on_stats' (e.g. savings: -500).
    2. Generate 'financial_explanation': BE SPECIFIC and ACCURATE to the numbers.
    3. Generate 'previous_outcome_title' (e.g. "Great job!", "Risky!", "Family is sad").
    4. Generate 'previous_outcome_desc'.
    5. Create the NEXT Situation ('narrative_hook') - Make it different from the last one.
    6. Provide 3 new choices.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Error generating next turn:", error);
    throw error;
  }
};

