const getContextualTip = (state: GameState): string => {
  const { debt, health, savings, profile, language } = state;

  let tipKey: keyof typeof TIP_DATABASE = 'default';

  // Priority 1: Critical Stats
  if (debt > 25000) {
    tipKey = 'high_debt';
  } else if (health < 40) {
    tipKey = 'low_health';
  } else if (savings < 2000) {
    tipKey = 'low_savings';
  } 
  // Priority 2: Role Specific
  else if (profile?.occupation && TIP_DATABASE[profile.occupation as keyof typeof TIP_DATABASE]) {
    tipKey = profile.occupation as keyof typeof TIP_DATABASE;
  }

  const tipObj = TIP_DATABASE[tipKey] || TIP_DATABASE['default'];
  return tipObj[language] || tipObj['en'];
};


// --- MAIN APP COMPONENT ---

// Default initial state
const initialState: GameState = {
  profile: null,
  language: 'en',
  savings: 0,
  debt: 0,
  happiness: 80,
  health: 80,
  turn: 1,
  history: [],
  statHistory: [],
  currentEvent: null,
  lastEventData: null,
  isLoading: false,
  error: null,
  gameStatus: 'ONBOARDING',
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(initialState);
  const [savedGameMeta, setSavedGameMeta] = useState<any>(null);

  // Check for save on mount
  useEffect(() => {
    const meta = getSavedGameMeta();
    setSavedGameMeta(meta);
  }, []);

  // Auto-save effect
  useEffect(() => {
    if (gameState.gameStatus === 'PLAYING' || gameState.gameStatus === 'FEEDBACK') {
      saveGame(gameState);
    }
  }, [gameState]);

  const handleLanguageChange = (lang: Language) => {
    setGameState(prev => ({ ...prev, language: lang }));
  };

  const handleContinueGame = () => {
    const savedState = loadGame();
    if (savedState) {
      setGameState(savedState);
    }
  };

  const handleStartGame = async (profile: PlayerProfile) => {
    // Clear any previous save when starting fresh
    clearSave();

    setGameState(prev => ({ 
      ...prev, 
      profile, 
      isLoading: true,
      // Initialize savings based on occupation
      savings: OCCUPATIONS.find(o => o.id === profile.occupation)?.baseSavings || 5000
    }));

    try {
      const eventData = await startSimulation(profile, gameState.language);
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        gameStatus: 'PLAYING',
        currentEvent: eventData,
        history: [...prev.history, eventData.narrative_hook]
      }));
    } catch (error) {
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        error: "Arth Mitra is having trouble connecting. Please try again."
      }));
    }
  };

  const handleChoice = async (choice: Choice) => {
    if (!gameState.currentEvent || !gameState.profile) return;

    setGameState(prev => ({ ...prev, isLoading: true, error: null }));

    try {
      // 1. Get AI Response (Impact + Next Turn)
      const resultData = await nextTurn(gameState, choice.id, choice.text, choice.cost_label);

      const impacts = resultData.impact_on_stats;

      // 2. Update Stats with Safe Parsing
      setGameState(prev => {
        const impactSavings = safeParseInt(impacts.savings);
        const impactDebt = safeParseInt(impacts.debt);
        const impactHappiness = safeParseInt(impacts.happiness);
        const impactHealth = safeParseInt(impacts.health);

        let newSavings = prev.savings + impactSavings;
        let newDebt = prev.debt + impactDebt;

        // Smart Balance Normalization
        // If savings go negative, debt increases.
        if (newSavings < 0) {
          newDebt += Math.abs(newSavings);
          newSavings = 0;
        }

        // If debt goes negative (overpaid), it flows back to savings.
        if (newDebt < 0) {
          newSavings += Math.abs(newDebt);
          newDebt = 0;
        }

        let newHappiness = prev.happiness + impactHappiness;
        let newHealth = prev.health + impactHealth;

        newHappiness = Math.min(100, Math.max(0, newHappiness));
        newHealth = Math.min(100, Math.max(0, newHealth));

        // 3. Record history (Actual delta after normalization)
        const actualChangeSavings = newSavings - prev.savings;
        const actualChangeDebt = newDebt - prev.debt;
        const actualChangeHappiness = newHappiness - prev.happiness;
        const actualChangeHealth = newHealth - prev.health;

        const newTransaction = {
          turn: prev.turn,
          description: choice.text,
          changes: {
            savings: actualChangeSavings,
            debt: actualChangeDebt,
            happiness: actualChangeHappiness,
            health: actualChangeHealth
          }
        };

        return {
          ...prev,
          isLoading: false,
          savings: newSavings,
          debt: newDebt,
          happiness: newHappiness,
          health: newHealth,
          turn: prev.turn + 1,
          statHistory: [...prev.statHistory, newTransaction],
          lastEventData: resultData, 
          currentEvent: resultData, 
          gameStatus: 'FEEDBACK'
        };
      });

    } catch (error) {
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        error: "Connection lost. Arth Mitra is thinking..."
      }));
    }
  };

  const handleNextTurn = () => {
    setGameState(prev => {
       const isDepressed = prev.happiness <= 0;
       const isSick = prev.health <= 0;
       const isHighDebt = prev.debt > 50000;
       const isMaxTurns = prev.turn >= 12;

       const isGameOver = isDepressed || isSick || isHighDebt || isMaxTurns || prev.lastEventData?.isGameOver;

       return {
         ...prev,
         gameStatus: isGameOver ? 'ENDED' : 'PLAYING'
       };
    });
  };

  const handleRestart = () => {
    clearSave(); // Clear save on explicit restart
    setGameState(initialState);
    setSavedGameMeta(null);
  };

  // Get current tip based on state
  const currentTip = useMemo(() => getContextualTip(gameState), [
    gameState.debt, 
    gameState.health, 
    gameState.savings, 
    gameState.profile?.occupation, 
    gameState.language,
    gameState.turn // Update tip every turn
  ]);

  return (
    // Outer Layout: Full height, flex column, hidden overflow
    <div className="h-full w-full flex flex-col bg-[#f0fdf9] text-neutral-dark font-sans overflow-hidden relative">

      {/* Background Gradient Layer */}
      <div className="absolute inset-0 z-0 bg-gradient-to-br from-[#f0fdf9] to-[#fff5f2] pointer-events-none" />

      {/* Header: Static, safe from overlap */}
      <div className="relative z-50 flex-none border-b border-white/20 shadow-sm bg-white/40 backdrop-blur-md">
        <Header language={gameState.language} onLanguageChange={handleLanguageChange} />
      </div>

      {/* Scrollable Main Area: Content pushes naturally */}
      <main className="relative z-0 flex-1 overflow-y-auto overflow-x-hidden w-full scroll-smooth">
        <div className="w-full max-w-[500px] mx-auto px-4 pb-12 flex flex-col min-h-full">

          {/* Error Banner */}
          {gameState.error && (
            <div className="mt-4 p-4 bg-accent-red/10 border border-accent-red/20 text-accent-red rounded-card animate-fade-in text-caption">
              {gameState.error}
            </div>
          )}

          {/* Onboarding */}
          {gameState.gameStatus === 'ONBOARDING' && (
            <div className="flex-1 flex flex-col justify-center py-6">
              <Onboarding 
                onComplete={handleStartGame} 
                isLoading={gameState.isLoading} 
                language={gameState.language}
                setLanguage={handleLanguageChange}
                savedGameMeta={savedGameMeta}
                onContinue={handleContinueGame}
              />
            </div>
          )}

          {/* Game Loop */}
          {(gameState.gameStatus === 'PLAYING' || gameState.gameStatus === 'FEEDBACK') && gameState.currentEvent && (
            <div className="flex flex-col w-full animate-fade-in">

              {/* Sticky Dashboard inside scroll area */}
              {/* Stacks naturally below Header visually, but sticks to top of scroll area */}
              <Dashboard state={gameState} />

              {/* Vertical spacing after dashboard */}
              <div className="h-6 shrink-0" /> 

              {/* Dynamic Content Area */}
              <div className="flex flex-col gap-6 w-full">
                {gameState.gameStatus === 'PLAYING' ? (
                  <ScenarioView 
                    event={gameState.currentEvent} 
                    onMakeChoice={handleChoice} 
                    isLoading={gameState.isLoading} 
                    state={gameState}
                  />
                ) : (
                  gameState.lastEventData && (
                    <FeedbackView 
                      lastEvent={gameState.lastEventData}
                      language={gameState.language}
                      onNext={handleNextTurn}
                    />
                  )
                )}

                {/* Contextual Financial Tip Section */}
                <FinancialTipCard 
                  key={gameState.turn} // Force re-render/animation on new turn
                  tip={currentTip} 
                  language={gameState.language} 
                />

              </div>
            </div>
          )}

          {/* Game Over */}
          {gameState.gameStatus === 'ENDED' && (
             <div className="flex-1 flex flex-col justify-center py-6">
              <GameOver state={gameState} onRestart={handleRestart} />
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { PlayerProfile, OCCUPATIONS, Language } from '../types';
import { getTranslation } from '../translations';
import { ArrowRight, Sparkles, Globe, Check, PlayCircle, Clock } from 'lucide-react';
import { playSound } from '../services/audioService';

interface OnboardingProps {
  onComplete: (profile: PlayerProfile) => void;
  isLoading: boolean;
  language: Language;
  setLanguage: (lang: Language) => void;
  savedGameMeta?: { name: string; occupation: string; turn: number; savings: number } | null;
  onContinue?: () => void;
}

export const Onboarding: React.FC<OnboardingProps> = ({ 
  onComplete, 
  isLoading, 
  language, 
  setLanguage, 
  savedGameMeta,
  onContinue 
}) => {
  // Steps: 0 = Language, 1 = Name, 2 = Occupation
  const [step, setStep] = useState<0 | 1 | 2>(0);
  const [name, setName] = useState('');
  const [selectedOccupation, setSelectedOccupation] = useState<string | null>(null);

  const handleLanguageSelect = (lang: Language) => {
    playSound('click');
    setLanguage(lang);
    // Short delay to let the user see their selection before transitioning
    setTimeout(() => {
       setStep(1);
    }, 250);
  };

  const handleResume = () => {
    playSound('success');
    if (onContinue) onContinue();
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    playSound('click');

    if (step === 1 && name) {
      setStep(2);
    } else if (step === 2 && name && selectedOccupation) {
      const occ = OCCUPATIONS.find(o => o.id === selectedOccupation);
      if (occ) {
        playSound('success'); // Play success sound when starting game
        onComplete({
          name,
          occupation: occ.id,
          monthlyIncome: occ.baseIncome,
        });
      }
    }
  };

  const handleOccupationSelect = (id: string) => {
    playSound('click');
    setSelectedOccupation(id);
  };

  const t = (key: any) => getTranslation(language, key);

  return (
    <div className="flex flex-col gap-6 pt-4 w-full max-w-md mx-auto">

      {/* STEP 0: LANGUAGE SELECTION & RESUME */}
      {step === 0 && (
        <div className="glass-card rounded-[32px] p-8 shadow-glass text-center animate-fade-in min-h-[420px] flex flex-col justify-center relative overflow-hidden">
           {/* Decorative background */}
           <div className="absolute top-0 right-0 w-32 h-32 bg-accent-yellow rounded-full blur-[60px] opacity-20 pointer-events-none"></div>
           <div className="absolute bottom-0 left-0 w-32 h-32 bg-brand rounded-full blur-[60px] opacity-10 pointer-events-none"></div>

           {/* RESUME CARD (If save exists) */}
           {savedGameMeta && (
             <div className="mb-8 relative z-10">
               <div className="text-left text-caption font-bold text-neutral-soft mb-2 ml-1 uppercase tracking-wide">Continue Journey</div>
               <button 
                 onClick={handleResume}
                 className="w-full bg-white/80 backdrop-blur-md border border-brand/20 p-5 rounded-[24px] shadow-sm hover:shadow-md hover:bg-white hover:-translate-y-0.5 transition-all text-left flex items-center gap-4 group"
               >
                 <div className="w-12 h-12 rounded-full bg-brand/10 text-brand flex items-center justify-center shrink-0">
                    <PlayCircle className="w-6 h-6 fill-brand/20" />
                 </div>
                 <div className="flex-1 min-w-0">
                    <h3 className="text-h3 font-bold text-brand truncate">{savedGameMeta.name}</h3>
                    <div className="flex items-center gap-3 text-caption text-neutral-soft font-medium mt-0.5">
                      <span className="flex items-center gap-1"><Clock size={12}/> Turn {savedGameMeta.turn}</span>
                      <span className="w-1 h-1 rounded-full bg-neutral-soft/30"></span>
                      <span>{savedGameMeta.occupation}</span>
                    </div>
                 </div>
                 <div className="text-brand opacity-0 group-hover:opacity-100 transition-opacity -translate-x-2 group-hover:translate-x-0 duration-300">
                    <ArrowRight size={20} />
                 </div>
               </button>
               <div className="relative flex py-5 items-center">
                  <div className="flex-grow border-t border-neutral-soft/20"></div>
                  <span className="flex-shrink-0 mx-4 text-neutral-soft/50 text-xs font-bold uppercase tracking-widest">Or New Game</span>
                  <div className="flex-grow border-t border-neutral-soft/20"></div>
               </div>
             </div>
           )}

           <div className="mb-6 space-y-2 relative">
             <div className="w-14 h-14 bg-white rounded-2xl shadow-sm flex items-center justify-center mx-auto text-brand transform rotate-3 mb-4">
                <Globe size={28} strokeWidth={1.5} />
             </div>
             <div>
                <h2 className="text-h2 text-brand font-bold tracking-tight">Choose Language</h2>
                <p className="text-body text-neutral-soft font-medium opacity-80">भाषा चुनें</p>
             </div>
           </div>

           <div className="flex flex-col gap-3 relative z-10">
             {(['en', 'hi', 'hinglish'] as Language[]).map((lang) => (
                <button
                  key={lang}
                  onClick={() => handleLanguageSelect(lang)}
                  className={`
                    w-full p-4 rounded-xl border flex items-center justify-between group transition-all duration-200 active:scale-95
                    ${language === lang 
                      ? 'bg-brand text-white border-brand shadow-md scale-[1.02]' 
                      : 'bg-white/50 border-white/60 hover:bg-white hover:border-brand/20 text-neutral-dark'}
                  `}
                >
                   <span className="text-h3 font-bold">{lang === 'en' ? 'English' : lang === 'hi' ? 'हिंदी (Hindi)' : 'Hinglish'}</span>
                   {language === lang && <Check size={20} className="text-white" />}
                </button>
             ))}
           </div>
        </div>
      )}

      {/* STEP 1 & 2: PROFILE SETUP */}
      {step > 0 && (
        <div className="glass-card rounded-[32px] p-8 shadow-glass relative overflow-hidden animate-fade-in">
          {/* Decorative background blobs */}
          <div className="absolute top-0 right-0 w-32 h-32 bg-accent-pink rounded-full blur-[60px] opacity-20 pointer-events-none"></div>
          <div className="absolute bottom-0 left-0 w-32 h-32 bg-accent-green rounded-full blur-[60px] opacity-20 pointer-events-none"></div>

          {/* Welcome Text (Only show on Step 1) */}
          {step === 1 && (
            <div className="text-center space-y-4 mb-8 relative animate-fade-in">
              <div className="inline-flex items-center justify-center p-3 bg-white rounded-2xl shadow-sm">
                <Sparkles className="w-6 h-6 text-accent-yellow" />
              </div>
              <h2 className="text-h1 text-brand tracking-tight">{t('welcome_title')}</h2>
              <p className="text-body text-neutral-soft leading-relaxed max-w-xs mx-auto">
                {t('welcome_subtitle')}
              </p>
            </div>
          )}

          {/* Step 2 Header */}
          {step === 2 && (
             <div className="text-center mb-6 animate-fade-in">
                <h2 className="text-h2 text-brand font-bold">{t('select_role')}</h2>
             </div>
          )}

          <form onSubmit={handleSubmit} className="relative flex flex-col gap-6">

            {/* Step 1: Name Input */}
            {step === 1 && (
              <div className="flex flex-col gap-6 animate-fade-in">
                <input
                  type="text"
                  id="name"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full p-6 text-center text-h2 font-bold bg-white/50 border-2 border-white/50 rounded-card text-brand placeholder-neutral-soft/50 focus:outline-none focus:bg-white focus:border-brand/30 transition-all"
                  placeholder={language === 'en' ? "Your Name..." : "आपका नाम..."}
                  autoFocus
                  required
                />

                <button
                  type="submit"
                  disabled={!name}
                  className={`w-full py-4 rounded-btn font-bold text-body shadow-btn transition-all flex items-center justify-center transform ${
                    !name 
                      ? 'bg-neutral-soft/20 text-neutral-soft cursor-not-allowed' 
                      : 'bg-brand text-white hover:-translate-y-0.5 hover:shadow-btn-hover'}
                  `}
                >
                  Start Journey <ArrowRight className="ml-2 w-5 h-5" />
                </button>
              </div>
            )}

            {/* Step 2: Role Selection */}
            {step === 2 && (
              <div className="flex flex-col gap-6 animate-fade-in">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  {OCCUPATIONS.map((occ) => (
                    <button
                      key={occ.id}
                      type="button"
                      onClick={() => handleOccupationSelect(occ.id)}
                      disabled={isLoading}
                      className={`
                        relative flex flex-col items-start p-4 rounded-card transition-all duration-300 text-left border
                        ${selectedOccupation === occ.id 
                          ? 'bg-white border-brand shadow-md ring-1 ring-brand' 
                          : 'bg-white/40 border-white hover:bg-white/80'}
                      `}
                    >
                      <span className="text-2xl mb-2">{occ.icon}</span>
                      <div className="w-full">
                        <div className="font-bold text-brand text-h3 leading-tight">
                          {occ.label[language] || occ.label['en']}
                        </div>
                        <div className="text-caption font-semibold text-neutral-soft uppercase tracking-wider mb-1">
                          {(occ as any).desc}
                        </div>
                      </div>
                    </button>
                  ))}
                </div>

                <button
                  type="submit"
                  disabled={!selectedOccupation || isLoading}
                  className={`
                    w-full py-4 rounded-btn font-bold text-body shadow-btn transition-all mt-2
                    ${!selectedOccupation || isLoading
                      ? 'bg-neutral-soft/20 text-neutral-soft cursor-not-allowed' 
                      : 'bg-brand text-white hover:-translate-y-0.5 hover:shadow-btn-hover'}
                  `}
                >
                  {isLoading ? (
                    <span className="flex items-center justify-center animate-pulse">
                      <Sparkles className="animate-spin -ml-1 mr-2 h-5 w-5" />
                      {t('loading')}
                    </span>
                  ) : (
                    t('start_button')
                  )}
                </button>
              </div>
            )}
          </form>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GameState } from '../types';
import { getTranslation } from '../translations';
import { IndianRupee, Heart, Smile, TrendingDown, TrendingUp } from 'lucide-react';
import { StatHistory } from './StatHistory';
import { playSound } from '../services/audioService';

interface DashboardProps {
  state: GameState;
}

const AnimatedCounter = ({ value, formatter }: { value: number, formatter?: (v: number) => string | number }) => {
  const [displayValue, setDisplayValue] = useState(value);
  const startTime = useRef<number>(0);
  const startValue = useRef<number>(value);
  const rafId = useRef<number | null>(null);

  useEffect(() => {
    startValue.current = displayValue;
    startTime.current = 0;

    const animate = (timestamp: number) => {
      if (!startTime.current) startTime.current = timestamp;
      const progress = timestamp - startTime.current;
      const duration = 1500;

      if (progress < duration) {
        const ease = 1 - Math.pow(2, -10 * (progress / duration));
        const nextValue = startValue.current + (value - startValue.current) * ease;
        setDisplayValue(nextValue);
        rafId.current = requestAnimationFrame(animate);
      } else {
        setDisplayValue(value);
      }
    };

    rafId.current = requestAnimationFrame(animate);
    return () => { if (rafId.current) cancelAnimationFrame(rafId.current); };
  }, [value]);

  return <>{formatter ? formatter(displayValue) : Math.round(displayValue)}</>;
};

interface StatChipProps {
  label: string;
  value: number;
  icon: React.ReactNode;
  onClick: () => void;
  formatter?: (v: number) => string | number;
  isHighGood?: boolean; // Defaults to true
  baseIconColor?: string;
}

const StatChip: React.FC<StatChipProps> = ({ 
  label, 
  value, 
  icon, 
  onClick, 
  formatter, 
  isHighGood = true,
  baseIconColor = "text-brand"
}) => {
  const [flashState, setFlashState] = useState<'idle' | 'good' | 'bad'>('idle');
  const prevValue = useRef(value);
  const isFirstRender = useRef(true);

  useEffect(() => {
    // Skip flash on mount
    if (isFirstRender.current) {
      isFirstRender.current = false;
      prevValue.current = value;
      return;
    }

    if (value !== prevValue.current) {
      const diff = value - prevValue.current;
      // If no change, do nothing
      if (diff === 0) return;

      const isIncrease = diff > 0;
      const isGoodOutcome = isHighGood ? isIncrease : !isIncrease;

      setFlashState(isGoodOutcome ? 'good' : 'bad');

      const timer = setTimeout(() => {
        setFlashState('idle');
      }, 600); // Flash duration

      prevValue.current = value;
      return () => clearTimeout(timer);
    }
  }, [value, isHighGood]);

  // Dynamic classes
  const baseClasses = "flex flex-col items-center justify-center p-3 rounded-chip min-w-[90px] min-h-[70px] backdrop-blur-md shadow-sm transition-all duration-300 active:scale-95 cursor-pointer hover:bg-white border flex-1 group relative overflow-hidden";

  let stateClasses = "bg-white/80 border-white/60";
  let iconColor = baseIconColor;

  if (flashState === 'good') {
    stateClasses = "bg-accent-green/10 border-accent-green/60 shadow-md ring-1 ring-accent-green/30";
    iconColor = "text-accent-green";
  } else if (flashState === 'bad') {
    stateClasses = "bg-accent-red/10 border-accent-red/60 shadow-md ring-1 ring-accent-red/30";
    iconColor = "text-accent-red";
  }

  return (
    <button onClick={onClick} className={`${baseClasses} ${stateClasses}`}>
      {/* Flash overlay */}
      <div className={`absolute inset-0 transition-opacity duration-500 pointer-events-none ${flashState === 'good' ? 'bg-accent-green/10 opacity-100' : 'opacity-0'} ${flashState === 'bad' ? 'bg-accent-red/10 opacity-100' : ''}`} />

      <div className={`relative z-10 flex items-center gap-1 mb-1 transition-colors duration-300 ${iconColor}`}>
         {icon}
      </div>
      <span className="relative z-10 text-[10px] font-bold uppercase text-neutral-soft tracking-wider">{label}</span>
      <span className="relative z-10 text-h3 text-neutral-dark mt-0.5">
         <AnimatedCounter value={value} formatter={formatter} />
      </span>
    </button>
  );
};

export const Dashboard: React.FC<DashboardProps> = ({ state }) => {
