};

import React, { useState, useMemo, useEffect } from 'react';
import { Header } from './components/Header';
import { Onboarding } from './components/Onboarding';
import { Dashboard } from './components/Dashboard';
import { ScenarioView } from './components/ScenarioView';
import { FeedbackView } from './components/FeedbackView';
import { GameOver } from './components/GameOver';
import { FinancialTipCard } from './components/FinancialTipCard';
import { GameState, PlayerProfile, Choice, Language, OCCUPATIONS } from './types';
import { startSimulation, nextTurn } from './services/geminiService';
import { saveGame, loadGame, clearSave, getSavedGameMeta } from './services/storageService';
import { TIP_DATABASE, getTip } from './data/tips';

// --- UTILS ---
const safeParseInt = (val: any): number => {
  if (typeof val === 'number') return Math.round(val);
  if (typeof val === 'string') {
    // Remove commas, currency symbols, and whitespace
    const clean = val.replace(/[^0-9.-]/g, '');
    return Math.round(Number(clean)) || 0;
  }
  return 0;
};

// --- TIP LOGIC ---

const getContextualTip = (state: GameState): string => {
  const { debt, health, savings, profile, language } = state;

  let tipKey: string = 'default';

  // Priority 1: Critical Stats
  if (debt > 25000) {
    tipKey = 'high_debt';
  } else if (health < 40) {
    tipKey = 'low_health';
  } else if (savings < 2000) {
    tipKey = 'low_savings';
  } 
  // Priority 2: Role Specific
  else if (profile?.occupation && TIP_DATABASE[profile.occupation]) {
    tipKey = profile.occupation;
  }

  return getTip(tipKey, language);
};


// --- MAIN APP COMPONENT ---

// Default initial state
const initialState: GameState = {
  profile: null,
  language: 'en',
  savings: 0,
  debt: 0,
  happiness: 80,
  health: 80,
  turn: 1,
  history: [],
  statHistory: [],
  currentEvent: null,
  lastEventData: null,
  isLoading: false,
  error: null,
  gameStatus: 'ONBOARDING',
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(initialState);
  const [savedGameMeta, setSavedGameMeta] = useState<any>(null);

  // Check for save on mount
  useEffect(() => {
    const meta = getSavedGameMeta();
    setSavedGameMeta(meta);
  }, []);

  // Auto-save effect
  useEffect(() => {
    if (gameState.gameStatus === 'PLAYING' || gameState.gameStatus === 'FEEDBACK') {
      saveGame(gameState);
    }
  }, [gameState]);

  const handleLanguageChange = (lang: Language) => {
    setGameState(prev => ({ ...prev, language: lang }));
  };

  const handleContinueGame = () => {
    const savedState = loadGame();
    if (savedState) {
      setGameState(savedState);
    }
  };

  const handleStartGame = async (profile: PlayerProfile) => {
    // Clear any previous save when starting fresh
    clearSave();

    setGameState(prev => ({ 
      ...prev, 
      profile, 
      isLoading: true,
      // Initialize savings based on occupation
      savings: OCCUPATIONS.find(o => o.id === profile.occupation)?.baseSavings || 5000
    }));

    try {
      const eventData = await startSimulation(profile, gameState.language);
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        gameStatus: 'PLAYING',
        currentEvent: eventData,
        history: [...prev.history, eventData.narrative_hook]
      }));
    } catch (error) {
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        error: "Arth Mitra is having trouble connecting. Please try again."
      }));
    }
  };

  const handleChoice = async (choice: Choice) => {
    if (!gameState.currentEvent || !gameState.profile) return;

    setGameState(prev => ({ ...prev, isLoading: true, error: null }));

    try {
      // 1. Get AI Response (Impact + Next Turn)
      const resultData = await nextTurn(gameState, choice.id, choice.text, choice.cost_label);

      const impacts = resultData.impact_on_stats;

      // 2. Update Stats with Safe Parsing
      setGameState(prev => {
        const impactSavings = safeParseInt(impacts.savings);
        const impactDebt = safeParseInt(impacts.debt);
        const impactHappiness = safeParseInt(impacts.happiness);
        const impactHealth = safeParseInt(impacts.health);

        let newSavings = prev.savings + impactSavings;
        let newDebt = prev.debt + impactDebt;

        // Smart Balance Normalization
        // If savings go negative, debt increases.
        if (newSavings < 0) {
          newDebt += Math.abs(newSavings);
          newSavings = 0;
        }

        // If debt goes negative (overpaid), it flows back to savings.
        if (newDebt < 0) {
          newSavings += Math.abs(newDebt);
          newDebt = 0;
        }

        let newHappiness = prev.happiness + impactHappiness;
        let newHealth = prev.health + impactHealth;

        newHappiness = Math.min(100, Math.max(0, newHappiness));
        newHealth = Math.min(100, Math.max(0, newHealth));

        // 3. Record history (Actual delta after normalization)
        const actualChangeSavings = newSavings - prev.savings;
        const actualChangeDebt = newDebt - prev.debt;
        const actualChangeHappiness = newHappiness - prev.happiness;
        const actualChangeHealth = newHealth - prev.health;

        const newTransaction = {
          turn: prev.turn,
          description: choice.text,
          changes: {
            savings: actualChangeSavings,
            debt: actualChangeDebt,
            happiness: actualChangeHappiness,
            health: actualChangeHealth
          }
        };

        return {
          ...prev,
          isLoading: false,
          savings: newSavings,
          debt: newDebt,
          happiness: newHappiness,
          health: newHealth,
          turn: prev.turn + 1,
          statHistory: [...prev.statHistory, newTransaction],
          lastEventData: resultData, 
          currentEvent: resultData, 
          gameStatus: 'FEEDBACK'
        };
      });

    } catch (error) {
      setGameState(prev => ({
        ...prev,
        isLoading: false,
        error: "Connection lost. Arth Mitra is thinking..."
      }));
    }
  };

  const handleNextTurn = () => {
    setGameState(prev => {
       const income = prev.profile?.monthlyIncome || 15000;

       // Dynamic Debt Limit: 6 months of income is a debt trap.
       const maxDebt = income * 6;

       const isDepressed = prev.happiness <= 5; 
       const isSick = prev.health <= 5; 
       const isHighDebt = prev.debt > maxDebt;
       const isMaxTurns = prev.turn >= 12;

       const isGameOver = isDepressed || isSick || isHighDebt || isMaxTurns || prev.lastEventData?.isGameOver;

       return {
         ...prev,
         gameStatus: isGameOver ? 'ENDED' : 'PLAYING'
       };
    });
  };

  const handleRestart = () => {
    clearSave(); // Clear save on explicit restart
    setGameState(initialState);
    setSavedGameMeta(null);
  };

  // Get current tip based on state
  const currentTip = useMemo(() => getContextualTip(gameState), [
    gameState.debt, 
    gameState.health, 
    gameState.savings, 
    gameState.profile?.occupation, 
    gameState.language,
    gameState.turn // Update tip every turn
  ]);

  return (
    // Outer Layout: Full height, flex column, hidden overflow
    <div className="h-full w-full flex flex-col bg-[#f0fdf9] text-neutral-dark font-sans overflow-hidden relative">

      {/* Background Gradient Layer */}
      <div className="absolute inset-0 z-0 bg-gradient-to-br from-[#f0fdf9] to-[#fff5f2] pointer-events-none" />

      {/* Header: Static, safe from overlap */}
      <div className="relative z-50 flex-none border-b border-white/20 shadow-sm bg-white/40 backdrop-blur-md">
        <Header language={gameState.language} onLanguageChange={handleLanguageChange} />
      </div>

      {/* Scrollable Main Area: Content pushes naturally */}
      <main className="relative z-0 flex-1 overflow-y-auto overflow-x-hidden w-full scroll-smooth">
        <div className="w-full max-w-[500px] mx-auto px-4 pb-12 flex flex-col min-h-full">

          {/* Error Banner */}
          {gameState.error && (
            <div className="mt-4 p-4 bg-accent-red/10 border border-accent-red/20 text-accent-red rounded-card animate-fade-in text-caption">
              {gameState.error}
            </div>
          )}

          {/* Onboarding */}
          {gameState.gameStatus === 'ONBOARDING' && (
            <div className="flex-1 flex flex-col justify-center py-6">
              <Onboarding 
                onComplete={handleStartGame} 
                isLoading={gameState.isLoading} 
                language={gameState.language}
                setLanguage={handleLanguageChange}
                savedGameMeta={savedGameMeta}
                onContinue={handleContinueGame}
              />
            </div>
          )}

          {/* Game Loop */}
          {(gameState.gameStatus === 'PLAYING' || gameState.gameStatus === 'FEEDBACK') && gameState.currentEvent && (
            <div className="flex flex-col w-full animate-fade-in">

              {/* Sticky Dashboard inside scroll area */}
              {/* Stacks naturally below Header visually, but sticks to top of scroll area */}
              <Dashboard state={gameState} />

              {/* Vertical spacing after dashboard */}
              <div className="h-6 shrink-0" /> 

              {/* Dynamic Content Area */}
              <div className="flex flex-col gap-6 w-full">
                {gameState.gameStatus === 'PLAYING' ? (
                  <ScenarioView 
                    event={gameState.currentEvent} 
                    onMakeChoice={handleChoice} 
                    isLoading={gameState.isLoading} 
                    state={gameState}
                  />
                ) : (
                  gameState.lastEventData && (
                    <FeedbackView 
                      lastEvent={gameState.lastEventData}
                      language={gameState.language}
                      onNext={handleNextTurn}
                    />
                  )
                )}

                {/* Contextual Financial Tip Section */}
                <FinancialTipCard 
                  key={gameState.turn} // Force re-render/animation on new turn
                  tip={currentTip} 
                  language={gameState.language} 
                />

              </div>
            </div>
          )}

          {/* Game Over */}
          {gameState.gameStatus === 'ENDED' && (
             <div className="flex-1 flex flex-col justify-center py-6">
              <GameOver state={gameState} onRestart={handleRestart} />
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useEffect } from 'react';
import { GameState } from '../types';
import { getTranslation } from '../translations';
import { RefreshCcw, Trophy, AlertTriangle, Skull, Frown, TrendingUp } from 'lucide-react';
import { playSound } from '../services/audioService';
import { getTip, TIP_DATABASE } from '../data/tips';

interface GameOverProps {
  state: GameState;
  onRestart: () => void;
}

export const GameOver: React.FC<GameOverProps> = ({ state, onRestart }) => {
  const t = (key: any) => getTranslation(state.language, key);

  // Dynamic Debt Thresholds
  // Game Over if Debt > 6 months of income
  // Survival (Yellow) if Debt > 4 months of income
  const income = state.profile?.monthlyIncome || 15000;
  const limitDebt = income * 6;
  const warningDebt = income * 4;

  // Determine Game Over Reason
  let reason: 'win' | 'debt' | 'health' | 'happiness' | 'survival' = 'win';
  let icon = <Trophy className="w-14 h-14 text-accent-green" />;
  let colorClass = 'bg-accent-green/20 border-white';

  if (state.debt > limitDebt) {
    reason = 'debt';
    icon = <AlertTriangle className="w-14 h-14 text-accent-red" />;
    colorClass = 'bg-accent-red/20 border-white';
  } else if (state.health <= 5) {
    reason = 'health';
    icon = <Skull className="w-14 h-14 text-accent-red" />;
    colorClass = 'bg-accent-red/20 border-white';
  } else if (state.happiness <= 5) {
    reason = 'happiness';
    icon = <Frown className="w-14 h-14 text-accent-yellow" />;
    colorClass = 'bg-accent-yellow/20 border-white';
  } else if (state.debt > warningDebt) {
    reason = 'survival'; // Reached end but High Debt
    icon = <AlertTriangle className="w-14 h-14 text-accent-yellow" />;
    colorClass = 'bg-accent-yellow/20 border-white';
  }

  const isPositiveOutcome = reason === 'win';

  useEffect(() => {
    if (isPositiveOutcome) {
      playSound('win');
    } else {
      playSound('lose');
    }
  }, [isPositiveOutcome]);

  // Get dynamic texts
  let title = t('game_over_win');
  let body = t('game_over_win_body');

  switch (reason) {
    case 'debt':
      title = t('game_over_debt_title');
      body = t('game_over_debt_body');
      break;
    case 'health':
      title = t('game_over_health_title');
      body = t('game_over_health_body');
      break;
    case 'happiness':
      title = t('game_over_happiness_title');
      body = t('game_over_happiness_body');
      break;
    case 'survival':
      title = t('game_over_survival_title');
      body = t('game_over_survival_body');
      break;
  }

  // Get Role specific tip for Debt from TIP_DATABASE
  const role = state.profile?.occupation || 'Worker';
  let tipText = '';

  if (reason === 'debt') {
    // Try to get specific bankruptcy tip, fallback to default bankruptcy tip
    const bankruptcyKey = `${role}_bankruptcy`;
    if (TIP_DATABASE[bankruptcyKey]) {
      tipText = getTip(bankruptcyKey, state.language);
    } else {
      tipText = getTip('default_bankruptcy', state.language);
    }
  }

  const handleRestartClick = () => {
    playSound('click');
    onRestart();
  };

  return (
    <div className="flex flex-col gap-6 text-center animate-fade-in pb-12 glass-card rounded-[32px] p-6 sm:p-8">
      <div className={`w-24 h-24 sm:w-28 sm:h-28 rounded-full flex items-center justify-center mx-auto shadow-inner border-4 ${colorClass}`}>
        {icon}
      </div>

      <div className="space-y-2 sm:space-y-4">
        <h2 className="text-h1 text-brand leading-tight">
          {title}
        </h2>
        <p className="text-body text-neutral-soft leading-relaxed px-2">
          {body}
        </p>
      </div>

      {/* RECOVERY TRICK CARD - Only show if Bankrupt */}
      {reason === 'debt' && (
        <div className="bg-white/80 border border-brand/20 p-5 rounded-2xl text-left shadow-sm relative overflow-hidden group">
          <div className="absolute top-0 right-0 w-16 h-16 bg-accent-yellow/10 rounded-bl-full -mr-2 -mt-2"></div>
          <div className="relative z-10">
             <h4 className="text-caption font-bold text-brand uppercase tracking-wider flex items-center gap-2 mb-2">
               {t('tip_title')}
             </h4>
             <div className="flex gap-3 items-start">
                <div className="bg-accent-yellow/20 p-2 rounded-full shrink-0 text-brand-dark mt-0.5">
                   <TrendingUp size={18} strokeWidth={2.5} />
                </div>
                <p className="text-body font-medium text-neutral-dark leading-snug">
                  {tipText}
                </p>
             </div>
          </div>
        </div>
      )}

      <div className="bg-white/50 backdrop-blur-sm p-4 sm:p-6 rounded-card border border-white/60 grid grid-cols-2 gap-3 sm:gap-4">
        <div className="p-2">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('savings')}</div>
          <div className="text-h3 font-bold text-neutral-dark">₹{state.savings.toLocaleString()}</div>
        </div>
        <div className="p-2">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('debt')}</div>
          <div className={`text-h3 font-bold ${state.debt > warningDebt ? 'text-accent-red' : 'text-neutral-dark'}`}>
            ₹{state.debt.toLocaleString()}
          </div>
        </div>
        <div className="p-2">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('happiness')}</div>
          <div className="text-h3 font-bold text-neutral-dark">{state.happiness}%</div>
        </div>
         <div className="p-2">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('health')}</div>
          <div className="text-h3 font-bold text-neutral-dark">{state.health}%</div>
        </div>
      </div>

      <button
        onClick={handleRestartClick}
        className="w-full inline-flex items-center justify-center px-10 py-4 bg-brand text-white rounded-btn font-bold text-body hover:shadow-btn-hover transition-all transform hover:-translate-y-0.5"
      >
        <RefreshCcw className="w-5 h-5 mr-3" />
        {t('restart')}
      </button>
    </div>
  );
};

