  currentEvent: GameEvent | null;
  lastEventData: GameEvent | null; // To show feedback for the just-completed turn

  isLoading: boolean;
  error: string | null;

  // Flow control
  gameStatus: 'ONBOARDING' | 'PLAYING' | 'FEEDBACK' | 'ENDED';
}

