export const getTranslation = (lang: Language, key: keyof typeof UI_TEXT) => {
  return UI_TEXT[key] ? (UI_TEXT[key][lang] || UI_TEXT[key]['en']) : key;
};

import { Howl, Howler } from 'howler';

const STORAGE_KEY_SFX = 'arth_mitra_sfx_vol';
const STORAGE_KEY_MUSIC = 'arth_mitra_bgm_vol';

// --- INITIALIZATION ---
// Get saved volumes or default to 0.5 (50%)
const getSavedVol = (key: string) => {
  if (typeof localStorage !== 'undefined') {
    const saved = localStorage.getItem(key);
    return saved !== null ? parseFloat(saved) : 0.5;
  }
  return 0.5;
};

let currentSfxVol = getSavedVol(STORAGE_KEY_SFX);
let currentMusicVol = getSavedVol(STORAGE_KEY_MUSIC);

// Initialize sounds with reliable CDN URLs
const soundAssets = {
  // Soft pop/click for UI interactions
  click: new Howl({ 
    src: ['https://assets.mixkit.co/active_storage/sfx/2568/2568-preview.mp3'], 
    preload: true
  }),
  // Pleasant chime for positive outcomes
  success: new Howl({ 
    src: ['https://assets.mixkit.co/active_storage/sfx/2019/2019-preview.mp3'], 
    preload: true
  }),
  // Low thud/tone for negative outcomes
  error: new Howl({ 
    src: ['https://assets.mixkit.co/active_storage/sfx/2572/2572-preview.mp3'], 
    preload: true
  }),
  // Celebratory tune for game win
  win: new Howl({ 
    src: ['https://assets.mixkit.co/active_storage/sfx/2020/2020-preview.mp3'], 
    preload: true
  }),
  // Sad/Somber tune for game loss
  lose: new Howl({ 
    src: ['https://assets.mixkit.co/active_storage/sfx/290/290-preview.mp3'], 
    preload: true
  }),
  // Calm ambient background music
  bgm: new Howl({
    src: ['https://assets.mixkit.co/active_storage/sfx/131/131-preview.mp3'], // Calm nature/birds/guitar ambience
    html5: true, // Use HTML5 Audio for larger files (streaming)
    loop: true,
    volume: currentMusicVol
  })
};

export type SoundType = keyof Omit<typeof soundAssets, 'bgm'>;

// --- SFX METHODS ---

export const playSound = (type: SoundType) => {
  try {
    const sound = soundAssets[type];

    // Stop previous instance if it's a UI click to prevent buildup
    if (type === 'click') {
        sound.rate(0.9 + Math.random() * 0.2); // Organic variation
    } else {
        sound.rate(1.0);
    }

    // Set volume specifically for this play instance based on global SFX setting
    sound.volume(currentSfxVol);
    sound.play();
  } catch (error) {
    console.warn('Audio playback failed:', error);
  }
};

export const setSfxVolume = (vol: number) => {
  currentSfxVol = Math.max(0, Math.min(1, vol));
  localStorage.setItem(STORAGE_KEY_SFX, currentSfxVol.toString());
};

export const getSfxVolume = () => currentSfxVol;

// --- MUSIC METHODS ---

export const initMusic = () => {
    // Browsers require interaction before playing audio. 
    // Call this on the first user click/interaction.
    if (!soundAssets.bgm.playing()) {
        soundAssets.bgm.volume(currentMusicVol);
        soundAssets.bgm.play();
        soundAssets.bgm.fade(0, currentMusicVol, 2000); // Fade in
    }
};

export const setMusicVolume = (vol: number) => {
  currentMusicVol = Math.max(0, Math.min(1, vol));
  soundAssets.bgm.volume(currentMusicVol);
  localStorage.setItem(STORAGE_KEY_MUSIC, currentMusicVol.toString());
};

export const getMusicVolume = () => currentMusicVol;

import React, { useState } from 'react';
import { X, Music, Volume2 } from 'lucide-react';
import { getTranslation } from '../translations';
import { Language } from '../types';
import { 
  getMusicVolume, 
  setMusicVolume, 
  getSfxVolume, 
  setSfxVolume,
  playSound 
} from '../services/audioService';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  language: Language;
}

export const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, language }) => {
  const [musicVol, setMusicVolState] = useState(getMusicVolume());
  const [sfxVol, setSfxVolState] = useState(getSfxVolume());

  if (!isOpen) return null;

  const t = (key: any) => getTranslation(language, key);

  const handleMusicChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newVal = parseFloat(e.target.value);
    setMusicVolState(newVal);
    setMusicVolume(newVal);
  };

  const handleSfxChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newVal = parseFloat(e.target.value);
    setSfxVolState(newVal);
    setSfxVolume(newVal);
  };

  const handleSfxRelease = () => {
    // Play a test sound when user finishes dragging sfx slider
    if (sfxVol > 0) playSound('click');
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center px-4">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-neutral-dark/40 backdrop-blur-sm animate-fade-in"
        onClick={onClose}
      />

      {/* Modal Content */}
      <div className="relative bg-white/90 backdrop-blur-md border border-white rounded-[32px] w-full max-w-sm p-6 shadow-2xl animate-fade-in transform transition-all scale-100">

        {/* Header */}
        <div className="flex items-center justify-between mb-8">
          <h2 className="text-h2 font-bold text-brand">{t('settings_title')}</h2>
          <button 
            onClick={() => { playSound('click'); onClose(); }}
            className="w-10 h-10 rounded-full bg-neutral-glass border border-white/50 flex items-center justify-center text-neutral-soft hover:bg-white hover:text-brand transition-all"
          >
            <X size={20} />
          </button>
        </div>

        {/* Controls */}
        <div className="space-y-8">

          {/* Music Control */}
          <div className="space-y-3">
            <div className="flex items-center justify-between">
               <div className="flex items-center gap-3 text-brand">
                 <Music size={20} />
                 <span className="text-body font-bold">{t('music_volume')}</span>
               </div>
               <span className="text-caption font-mono text-neutral-soft bg-white/50 px-2 py-1 rounded-lg">
                 {Math.round(musicVol * 100)}%
               </span>
            </div>
            <input
              type="range"
              min="0"
              max="1"
              step="0.01"
              value={musicVol}
              onChange={handleMusicChange}
              className="w-full h-2 bg-neutral-200 rounded-lg appearance-none cursor-pointer accent-brand"
            />
          </div>

          {/* SFX Control */}
          <div className="space-y-3">
            <div className="flex items-center justify-between">
               <div className="flex items-center gap-3 text-brand">
                 <Volume2 size={20} />
                 <span className="text-body font-bold">{t('sfx_volume')}</span>
               </div>
               <span className="text-caption font-mono text-neutral-soft bg-white/50 px-2 py-1 rounded-lg">
                 {Math.round(sfxVol * 100)}%
               </span>
            </div>
            <input
              type="range"
              min="0"
              max="1"
              step="0.01"
              value={sfxVol}
              onChange={handleSfxChange}
              onMouseUp={handleSfxRelease}
              onTouchEnd={handleSfxRelease}
              className="w-full h-2 bg-neutral-200 rounded-lg appearance-none cursor-pointer accent-accent-green"
            />
          </div>

        </div>

        {/* Footer */}
        <button 
          onClick={() => { playSound('click'); onClose(); }}
          className="w-full mt-8 py-3 bg-brand text-white rounded-btn font-bold text-body shadow-btn hover:shadow-btn-hover hover:-translate-y-0.5 transition-all"
        >
          {t('close')}
        </button>

      </div>
    </div>
  );
};

