import React, { useEffect } from 'react';
import { GameState } from '../types';
import { getTranslation } from '../translations';
import { RefreshCcw, Trophy, AlertTriangle, Skull, Frown, TrendingUp } from 'lucide-react';
import { playSound } from '../services/audioService';
import { getTip, TIP_DATABASE } from '../data/tips';

interface GameOverProps {
  state: GameState;
  onRestart: () => void;
}

export const GameOver: React.FC<GameOverProps> = ({ state, onRestart }) => {
  const t = (key: any) => getTranslation(state.language, key);

  // Dynamic Debt Thresholds
  // Game Over if Debt > 6 months of income (Critical Bankruptcy)
  // Survival (Yellow) if Debt > 4 months of income (Heavy Burden)
  const income = state.profile?.monthlyIncome || 15000;
  const debtThreshold = income * 6;
  const warningDebt = income * 4;

  // Determine Game Over Reason
  // Priority: Debt > Health > Happiness > Survival > Win
  let reason: 'win' | 'debt' | 'health' | 'happiness' | 'survival' = 'win';
  let icon = <Trophy className="w-14 h-14 text-accent-green" />;
  let colorClass = 'bg-accent-green/20 border-white';

  if (state.debt > debtThreshold) {
    reason = 'debt';
    icon = <AlertTriangle className="w-14 h-14 text-accent-red" />;
    colorClass = 'bg-accent-red/20 border-white';
  } else if (state.health <= 5) {
    reason = 'health';
    icon = <Skull className="w-14 h-14 text-accent-red" />;
    colorClass = 'bg-accent-red/20 border-white';
  } else if (state.happiness <= 5) {
    reason = 'happiness';
    icon = <Frown className="w-14 h-14 text-accent-yellow" />;
    colorClass = 'bg-accent-yellow/20 border-white';
  } else if (state.debt > warningDebt) {
    reason = 'survival'; // Reached end but High Debt
    icon = <AlertTriangle className="w-14 h-14 text-accent-yellow" />;
    colorClass = 'bg-accent-yellow/20 border-white';
  }

  const isPositiveOutcome = reason === 'win';

  useEffect(() => {
    if (isPositiveOutcome) {
      playSound('win');
    } else {
      playSound('lose');
    }
  }, [isPositiveOutcome]);

  // Get dynamic texts
  let title = t('game_over_win');
  let body = t('game_over_win_body');

  switch (reason) {
    case 'debt':
      title = t('game_over_debt_title');
      body = t('game_over_debt_body');
      break;
    case 'health':
      title = t('game_over_health_title');
      body = t('game_over_health_body');
      break;
    case 'happiness':
      title = t('game_over_happiness_title');
      body = t('game_over_happiness_body');
      break;
    case 'survival':
      title = t('game_over_survival_title');
      body = t('game_over_survival_body');
      break;
  }

  // Get Role specific tip for Debt from TIP_DATABASE
  const role = state.profile?.occupation || 'Worker';
  let tipText = '';

  if (reason === 'debt') {
    // Try to get specific bankruptcy tip, fallback to default bankruptcy tip
    const bankruptcyKey = `${role}_bankruptcy`;
    if (TIP_DATABASE[bankruptcyKey]) {
      tipText = getTip(bankruptcyKey, state.language);
    } else {
      tipText = getTip('default_bankruptcy', state.language);
    }
  }

  const handleRestartClick = () => {
    playSound('click');
    onRestart();
  };

  return (
    <div className="flex flex-col gap-6 text-center animate-fade-in pb-12 glass-card rounded-[32px] p-6 sm:p-8">
      <div className={`w-24 h-24 sm:w-28 sm:h-28 rounded-full flex items-center justify-center mx-auto shadow-inner border-4 ${colorClass}`}>
        {icon}
      </div>

      <div className="space-y-2 sm:space-y-4">
        <h2 className="text-h1 text-brand leading-tight">
          {title}
        </h2>
        <p className="text-body text-neutral-soft leading-relaxed px-2">
          {body}
        </p>
      </div>

      {/* RECOVERY TRICK CARD - Only show if Bankrupt */}
      {reason === 'debt' && (
        <div className="bg-white/80 border border-brand/20 p-5 rounded-2xl text-left shadow-sm relative overflow-hidden group">
          <div className="absolute top-0 right-0 w-16 h-16 bg-accent-yellow/10 rounded-bl-full -mr-2 -mt-2"></div>
          <div className="relative z-10">
             <h4 className="text-caption font-bold text-brand uppercase tracking-wider flex items-center gap-2 mb-2">
               {t('tip_title')}
             </h4>
             <div className="flex gap-3 items-start">
                <div className="bg-accent-yellow/20 p-2 rounded-full shrink-0 text-brand-dark mt-0.5">
                   <TrendingUp size={18} strokeWidth={2.5} />
                </div>
                <p className="text-body font-medium text-neutral-dark leading-snug">
                  {tipText}
                </p>
             </div>
          </div>
        </div>
      )}

      <div className="bg-white/50 backdrop-blur-sm p-4 sm:p-6 rounded-card border border-white/60 grid grid-cols-2 gap-3 sm:gap-4">
        <div className="p-2">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('savings')}</div>
          <div className="text-h3 font-bold text-neutral-dark">₹{state.savings.toLocaleString()}</div>
        </div>
        <div className="p-2">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('debt')}</div>
          <div className={`text-h3 font-bold ${state.debt > warningDebt ? 'text-accent-red' : 'text-neutral-dark'}`}>
            ₹{state.debt.toLocaleString()}
          </div>
        </div>
        <div className="p-2">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('happiness')}</div>
          <div className="text-h3 font-bold text-neutral-dark">{state.happiness}%</div>
        </div>
         <div className="p-2">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('health')}</div>
          <div className="text-h3 font-bold text-neutral-dark">{state.health}%</div>
        </div>
         <div className="p-2 col-span-2 sm:col-span-1 sm:col-start-1 sm:col-end-3">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('relationships')}</div>
          <div className="text-h3 font-bold text-neutral-dark">{state.relationships || 50}%</div>
        </div>
      </div>

      <button
        onClick={handleRestartClick}
        className="w-full inline-flex items-center justify-center px-10 py-4 bg-brand text-white rounded-btn font-bold text-body hover:shadow-btn-hover transition-all transform hover:-translate-y-0.5"
      >
        <RefreshCcw className="w-5 h-5 mr-3" />
        {t('restart')}
      </button>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GameState } from '../types';
import { getTranslation } from '../translations';
import { IndianRupee, Heart, Smile, TrendingDown, TrendingUp, Users } from 'lucide-react';
import { StatHistory } from './StatHistory';
import { playSound } from '../services/audioService';

interface DashboardProps {
  state: GameState;
}

const AnimatedCounter = ({ value, formatter }: { value: number, formatter?: (v: number) => string | number }) => {
  const [displayValue, setDisplayValue] = useState(value);
  const startTime = useRef<number>(0);
  const startValue = useRef<number>(value);
  const rafId = useRef<number | null>(null);

  useEffect(() => {
    startValue.current = displayValue;
    startTime.current = 0;

    const animate = (timestamp: number) => {
      if (!startTime.current) startTime.current = timestamp;
      const progress = timestamp - startTime.current;
      const duration = 800; // Faster animation

      if (progress < duration) {
        const ease = 1 - Math.pow(2, -10 * (progress / duration));
        const nextValue = startValue.current + (value - startValue.current) * ease;
        setDisplayValue(nextValue);
        rafId.current = requestAnimationFrame(animate);
      } else {
        setDisplayValue(value);
      }
    };

    rafId.current = requestAnimationFrame(animate);
    return () => { if (rafId.current) cancelAnimationFrame(rafId.current); };
  }, [value]);

  return <>{formatter ? formatter(displayValue) : Math.round(displayValue)}</>;
};

interface StatChipProps {
  label: string;
  value: number;
  icon: React.ReactNode;
  onClick: () => void;
  formatter?: (v: number) => string | number;
  isHighGood?: boolean; // Defaults to true
  baseIconColor?: string;
}

const StatChip: React.FC<StatChipProps> = ({ 
  label, 
  value, 
  icon, 
  onClick, 
  formatter, 
  isHighGood = true,
  baseIconColor = "text-brand"
}) => {
  const [flashState, setFlashState] = useState<'idle' | 'good' | 'bad'>('idle');
  const [isPulsing, setIsPulsing] = useState(false);
  const prevValue = useRef(value);
  const isFirstRender = useRef(true);

  useEffect(() => {
    // Skip flash on mount
    if (isFirstRender.current) {
      isFirstRender.current = false;
      prevValue.current = value;
      return;
    }

    if (value !== prevValue.current) {
      const diff = value - prevValue.current;
      // If no change, do nothing
      if (diff === 0) return;

      const isIncrease = diff > 0;
      const isGoodOutcome = isHighGood ? isIncrease : !isIncrease;

      setFlashState(isGoodOutcome ? 'good' : 'bad');
      setIsPulsing(true);

      const timer = setTimeout(() => {
        setFlashState('idle');
        setIsPulsing(false);
      }, 600); // Flash duration

      prevValue.current = value;
      return () => clearTimeout(timer);
    }
  }, [value, isHighGood]);

  // Dynamic classes
  const baseClasses = "flex flex-col items-center justify-center p-3 rounded-chip min-w-[70px] sm:min-w-[90px] min-h-[70px] backdrop-blur-md shadow-sm transition-all duration-300 active:scale-95 cursor-pointer hover:bg-white border flex-1 group relative overflow-hidden";

  let stateClasses = "bg-white/80 border-white/60";
  let iconColor = baseIconColor;

  if (flashState === 'good') {
    stateClasses = "bg-accent-green/10 border-accent-green/60 shadow-md ring-1 ring-accent-green/30";
    iconColor = "text-accent-green";
  } else if (flashState === 'bad') {
    stateClasses = "bg-accent-red/10 border-accent-red/60 shadow-md ring-1 ring-accent-red/30";
    iconColor = "text-accent-red";
  }

  // Add scale pulse effect
  const transformClass = isPulsing ? "scale-105" : "scale-100";

  return (
    <button onClick={onClick} className={`${baseClasses} ${stateClasses} ${transformClass}`}>
      {/* Flash overlay */}
      <div className={`absolute inset-0 transition-opacity duration-500 pointer-events-none ${flashState === 'good' ? 'bg-accent-green/10 opacity-100' : 'opacity-0'} ${flashState === 'bad' ? 'bg-accent-red/10 opacity-100' : ''}`} />

      <div className={`relative z-10 flex items-center gap-1 mb-1 transition-colors duration-300 ${iconColor}`}>
         {icon}
      </div>
      <span className="relative z-10 text-[9px] sm:text-[10px] font-bold uppercase text-neutral-soft tracking-wider text-center leading-tight">{label}</span>
      <span className="relative z-10 text-h3 text-neutral-dark mt-0.5">
         <AnimatedCounter value={value} formatter={formatter} />
      </span>
    </button>
  );
};

export const Dashboard: React.FC<DashboardProps> = ({ state }) => {
  const [selectedStat, setSelectedStat] = useState<'savings' | 'debt' | 'happiness' | 'health' | 'relationships' | null>(null);

  const t = (key: any) => getTranslation(state.language, key);

  const savingsFormatter = (val: number) => {
    if (val > -1000 && val < 1000) return Math.round(val);
    return `${(val / 1000).toFixed(1)}k`;
  };

  const debtFormatter = (val: number) => {
    if (Math.round(val) <= 0) return '-';
    return `${(val / 1000).toFixed(1)}k`;
  };

  const percentageFormatter = (val: number) => {
    return `${Math.round(val)}%`;
  };

  const handleStatClick = (stat: 'savings' | 'debt' | 'happiness' | 'health' | 'relationships') => {
    playSound('click');
    setSelectedStat(stat);
  };

  return (
    <>
      {/* 
        Sticky Container 
        - top-0 relative to the scrollable main container in App.tsx 
        - -mx-4 to expand full width of container padding
        - Strong background to hide scrolling content
      */}
      <div className="sticky top-0 z-40 -mx-4 px-4 pt-4 pb-4 overflow-x-auto scrollbar-hide bg-[#f0fdf9]/95 backdrop-blur-md border-b border-white/20 shadow-sm transition-all">
        <div className="flex gap-2 sm:gap-3 w-full justify-between">

          <StatChip 
            label={t('savings')} 
            value={state.savings} 
            formatter={savingsFormatter}
            onClick={() => handleStatClick('savings')}
            icon={<IndianRupee className="w-4 h-4" strokeWidth={2.5} />}
            baseIconColor="text-accent-green"
            isHighGood={true}
          />

          <StatChip 
            label={t('debt')} 
            value={state.debt} 
            formatter={debtFormatter}
            onClick={() => handleStatClick('debt')}
            icon={state.debt > 0 ? <TrendingDown className="w-4 h-4" strokeWidth={2.5} /> : <TrendingUp className="w-4 h-4" strokeWidth={2.5} />}
            baseIconColor={state.debt > 0 ? 'text-accent-red' : 'text-neutral-soft'}
            isHighGood={false}
          />

          <StatChip 
            label={t('happiness')} 
            value={state.happiness} 
            formatter={percentageFormatter}
            onClick={() => handleStatClick('happiness')}
            icon={<Smile className="w-4 h-4" strokeWidth={2.5} />}
            baseIconColor="text-accent-yellow"
            isHighGood={true}
          />

          <StatChip 
            label={t('health')} 
            value={state.health} 
            formatter={percentageFormatter}
            onClick={() => handleStatClick('health')}
            icon={<Heart className="w-4 h-4 fill-current" />}
            baseIconColor="text-accent-pink"
            isHighGood={true}
          />

          <StatChip 
            label={t('relationships')} 
            value={state.relationships || 50} 
            formatter={percentageFormatter}
            onClick={() => handleStatClick('relationships')}
            icon={<Users className="w-4 h-4" strokeWidth={2.5} />}
            baseIconColor="text-accent-purple"
            isHighGood={true}
          />

        </div>
      </div>

      {selectedStat && (
        <StatHistory 
          type={selectedStat} 
          history={state.statHistory} 
          onClose={() => setSelectedStat(null)}
          title={t(selectedStat)}
        />
      )}
    </>
  );
};

