import React, { useEffect } from 'react';
import { GameState } from '../types';
import { getTranslation } from '../translations';
import { RefreshCcw, Trophy, AlertTriangle, Skull, Frown, TrendingUp, Heart, Smile } from 'lucide-react';
import { playSound } from '../services/audioService';
import { getTip, TIP_DATABASE } from '../data/tips';

interface GameOverProps {
  state: GameState;
  onRestart: () => void;
}

export const GameOver: React.FC<GameOverProps> = ({ state, onRestart }) => {
  const t = (key: any) => getTranslation(state.language, key);

  // Dynamic Debt Thresholds
  const income = state.profile?.monthlyIncome || 15000;
  const debtThreshold = income * 6;
  const warningDebt = income * 4;

  let reason: 'win' | 'debt' | 'health' | 'happiness' | 'survival' = 'win';
  let icon = <Trophy className="w-14 h-14 text-accent-green" />;
  let colorClass = 'bg-accent-green/20 border-white';

  if (state.debt > debtThreshold) {
    reason = 'debt';
    icon = <AlertTriangle className="w-14 h-14 text-accent-red" />;
    colorClass = 'bg-accent-red/20 border-white';
  } else if (state.health <= 5) {
    reason = 'health';
    icon = <Skull className="w-14 h-14 text-accent-red" />;
    colorClass = 'bg-accent-red/20 border-white';
  } else if (state.happiness <= 5) {
    reason = 'happiness';
    icon = <Frown className="w-14 h-14 text-accent-yellow" />;
    colorClass = 'bg-accent-yellow/20 border-white';
  } else if (state.debt > warningDebt) {
    reason = 'survival'; // Reached end but High Debt
    icon = <AlertTriangle className="w-14 h-14 text-accent-yellow" />;
    colorClass = 'bg-accent-yellow/20 border-white';
  }

  const isPositiveOutcome = reason === 'win';

  useEffect(() => {
    if (isPositiveOutcome) {
      playSound('win');
    } else {
      playSound('lose');
    }
  }, [isPositiveOutcome]);

  // Get dynamic texts
  let title = t('game_over_win');
  let body = t('game_over_win_body');

  switch (reason) {
    case 'debt':
      title = t('game_over_debt_title');
      body = t('game_over_debt_body');
      break;
    case 'health':
      title = t('game_over_health_title');
      body = t('game_over_health_body');
      break;
    case 'happiness':
      title = t('game_over_happiness_title');
      body = t('game_over_happiness_body');
      break;
    case 'survival':
      title = t('game_over_survival_title');
      body = t('game_over_survival_body');
      break;
  }

  // Get Specific Recovery Tips based on Reason
  const role = state.profile?.occupation || 'Worker';
  let tipText = '';
  let tipIcon = <TrendingUp size={18} strokeWidth={2.5} />; // Default icon

  if (reason === 'debt') {
    // Role-specific bankruptcy tip
    const bankruptcyKey = `${role}_bankruptcy`;
    tipText = TIP_DATABASE[bankruptcyKey] 
      ? getTip(bankruptcyKey, state.language) 
      : getTip('default_bankruptcy', state.language);
  } else if (reason === 'survival') {
    tipText = getTip('recovery_survival', state.language);
  } else if (reason === 'health') {
    // Try role-specific health tip first
    const healthKey = `${role}_health_recovery`;
    tipText = TIP_DATABASE[healthKey]
        ? getTip(healthKey, state.language)
        : getTip('recovery_health', state.language);
    tipIcon = <Heart size={18} strokeWidth={2.5} />;
  } else if (reason === 'happiness') {
    // Try role-specific happiness tip first
    const happyKey = `${role}_happiness_recovery`;
    tipText = TIP_DATABASE[happyKey]
        ? getTip(happyKey, state.language)
        : getTip('recovery_happiness', state.language);
    tipIcon = <Smile size={18} strokeWidth={2.5} />;
  }

  const handleRestartClick = () => {
    playSound('click');
    onRestart();
  };

  return (
    <div className="flex flex-col gap-6 text-center pb-12 glass-card rounded-[32px] p-6 sm:p-8 animate-fade-in">

      {/* Icon with Pop In & Bounce */}
      <div className={`w-24 h-24 sm:w-28 sm:h-28 rounded-full flex items-center justify-center mx-auto shadow-inner border-4 ${colorClass} opacity-0 animate-pop-in`}>
        <div className="animate-bounce-subtle">
           {icon}
        </div>
      </div>

      <div className="space-y-2 sm:space-y-4 opacity-0 animate-fade-in-up" style={{ animationDelay: '200ms' }}>
        <h2 className="text-h1 text-brand leading-tight">
          {title}
        </h2>
        <p className="text-body text-neutral-soft leading-relaxed px-2">
          {body}
        </p>
      </div>

      {/* RECOVERY TRICK CARD - Shows for all failure/warning states */}
      {tipText && (
        <div className="bg-white/80 border border-brand/20 p-5 rounded-2xl text-left shadow-sm relative overflow-hidden group opacity-0 animate-slide-in-right" style={{ animationDelay: '400ms' }}>
          <div className="absolute top-0 right-0 w-16 h-16 bg-accent-yellow/10 rounded-bl-full -mr-2 -mt-2"></div>
          <div className="relative z-10">
             <h4 className="text-caption font-bold text-brand uppercase tracking-wider flex items-center gap-2 mb-2">
               {t('tip_title')}
             </h4>
             <div className="flex gap-3 items-start">
                <div className="bg-accent-yellow/20 p-2 rounded-full shrink-0 text-brand-dark mt-0.5">
                   {tipIcon}
                </div>
                <p className="text-body font-medium text-neutral-dark leading-snug">
                  {tipText}
                </p>
             </div>
          </div>
        </div>
      )}

      {/* Stats Grid */}
      <div className="bg-white/50 backdrop-blur-sm p-4 sm:p-6 rounded-card border border-white/60 grid grid-cols-2 gap-3 sm:gap-4 opacity-0 animate-fade-in-up" style={{ animationDelay: '500ms' }}>
        <div className="p-2">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('savings')}</div>
          <div className="text-h3 font-bold text-neutral-dark">₹{state.savings.toLocaleString()}</div>
        </div>
        <div className="p-2">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('debt')}</div>
          <div className={`text-h3 font-bold ${state.debt > warningDebt ? 'text-accent-red' : 'text-neutral-dark'}`}>
            ₹{state.debt.toLocaleString()}
          </div>
        </div>
        <div className="p-2">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('happiness')}</div>
          <div className="text-h3 font-bold text-neutral-dark">{state.happiness}%</div>
        </div>
         <div className="p-2">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('health')}</div>
          <div className="text-h3 font-bold text-neutral-dark">{state.health}%</div>
        </div>
         <div className="p-2 col-span-2 sm:col-span-1 sm:col-start-1 sm:col-end-3">
          <div className="text-caption text-neutral-soft uppercase tracking-widest font-bold mb-1">{t('relationships')}</div>
          <div className="text-h3 font-bold text-neutral-dark">{state.relationships || 50}%</div>
        </div>
      </div>

      <button
        onClick={handleRestartClick}
        className="w-full inline-flex items-center justify-center px-10 py-4 bg-brand text-white rounded-btn font-bold text-body hover:shadow-btn-hover transition-all transform hover:-translate-y-0.5 opacity-0 animate-fade-in"
        style={{ animationDelay: '800ms' }}
      >
        <RefreshCcw className="w-5 h-5 mr-3" />
        {t('restart')}
      </button>
    </div>
  );
};

import React from 'react';
import { StatTransaction } from '../types';
import { X, IndianRupee, TrendingUp, TrendingDown, Smile, Heart, Users, Plus, Minus } from 'lucide-react';
import { playSound } from '../services/audioService';

interface StatHistoryProps {
  type: 'savings' | 'debt' | 'happiness' | 'health' | 'relationships';
  history: StatTransaction[];
  onClose: () => void;
  title: string;
}

export const StatHistory: React.FC<StatHistoryProps> = ({ type, history, onClose, title }) => {
  // Filter history to only show transactions where the specific stat changed
  // Handle undefined relationships for old saves safely
  const filteredHistory = history.filter(t => (t.changes[type] || 0) !== 0).reverse();

  const handleClose = () => {
    playSound('click');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center px-4">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-neutral-dark/40 backdrop-blur-sm animate-fade-in" 
        onClick={handleClose}
      />

      {/* Modal Content */}
      <div className="bg-white rounded-[32px] w-full max-w-sm max-h-[70vh] flex flex-col shadow-2xl animate-fade-in relative z-10 overflow-hidden">

        {/* Header */}
        <div className="p-6 border-b border-neutral-100 flex items-center justify-between bg-neutral-50/50">
          <h3 className="text-h3 font-bold text-neutral-dark capitalize flex items-center gap-2">
            {type === 'savings' && <IndianRupee className="w-5 h-5 text-accent-green" />}
            {type === 'debt' && <TrendingUp className="w-5 h-5 text-accent-red" />}
            {type === 'happiness' && <Smile className="w-5 h-5 text-accent-yellow" />}
            {type === 'health' && <Heart className="w-5 h-5 text-accent-pink" />}
            {type === 'relationships' && <Users className="w-5 h-5 text-accent-purple" />}
            {title} History
          </h3>
          <button 
            onClick={handleClose}
            className="w-8 h-8 rounded-full bg-white border border-neutral-200 flex items-center justify-center text-neutral-soft hover:bg-neutral-100 transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* List */}
        <div className="overflow-y-auto p-4 flex flex-col gap-3">
          {filteredHistory.length === 0 ? (
            <div className="text-center py-8 text-neutral-soft text-caption">
              No history yet for this stat.
            </div>
          ) : (
            filteredHistory.map((item, index) => {
              const change = item.changes[type] || 0;
              const isIncrease = change > 0;

              // Determine if the change is "Good" for the player
              let isGood = false;
              if (type === 'debt') {
                isGood = !isIncrease; // Debt going DOWN is Good
              } else {
                isGood = isIncrease; // Others going UP is Good
              }

              const colorClass = isGood ? "text-accent-green" : "text-accent-red";
              const bgClass = isGood ? "bg-accent-green/10" : "bg-accent-red/10";
              const borderClass = isGood ? "border-l-accent-green" : "border-l-accent-red";

              // Select semantic icon
              let Icon = isIncrease ? TrendingUp : TrendingDown;
              // For money, use Plus/Minus for clarity
              if (type === 'savings' || type === 'debt') {
                 Icon = isIncrease ? Plus : Minus;
              }

              return (
                <div key={index} className={`flex items-center justify-between p-3 pl-4 rounded-xl bg-white border border-neutral-100 shadow-sm border-l-4 ${borderClass}`}>
                  <div className="flex items-center gap-3 overflow-hidden">
                    {/* Icon Indicator */}
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${bgClass} ${colorClass}`}>
                       <Icon className="w-4 h-4" strokeWidth={3} />
                    </div>

                    {/* Description */}
                    <div className="flex flex-col min-w-0">
                      <span className="text-body font-bold text-neutral-dark leading-tight truncate pr-2">{item.description}</span>
                      <span className="text-[10px] text-neutral-soft font-bold uppercase tracking-wider mt-0.5">Turn {item.turn}</span>
                    </div>
                  </div>

                  {/* Value */}
                  <div className={`text-h3 font-bold ${colorClass} whitespace-nowrap ml-2`}>
                    {change > 0 ? '+' : ''}{change}{type === 'savings' || type === 'debt' ? '' : '%'}
                  </div>
                </div>
              );
            })
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { GameEvent, Language } from '../types';
import { getTranslation } from '../translations';
import { TrendingUp, TrendingDown, Heart, Smile, ArrowRight, IndianRupee, Info, ChevronDown, Users, Share2, Check } from 'lucide-react';
import { playSound } from '../services/audioService';

interface FeedbackViewProps {
  lastEvent: GameEvent;
  language: Language;
  onNext: () => void;
}

export const FeedbackView: React.FC<FeedbackViewProps> = ({ lastEvent, language, onNext }) => {
  const impacts = lastEvent.impact_on_stats;
  const [isExpanded, setIsExpanded] = useState(false);
  const [showCopied, setShowCopied] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!impacts) return;

    // Play sound based on result
    const isBadOutcome = (impacts.debt > 500) || (impacts.happiness < -5) || (impacts.health < -5) || (impacts.relationships < -5);
    const isGoodOutcome = (impacts.savings > 0) || (impacts.happiness > 5) || (impacts.relationships > 5);

    if (isBadOutcome) {
      playSound('error');
    } else if (isGoodOutcome) {
      playSound('success');
    } else {
      playSound('click'); // Neutral
    }
  }, [lastEvent]); 

  // Reset expansion state when event changes
  useEffect(() => {
    setIsExpanded(false);
    setShowCopied(false);
  }, [lastEvent]);

  if (!impacts) return null;

  const t = (key: any) => getTranslation(language, key);

  const handleNextClick = () => {
    playSound('click');
    onNext();
  };

  const handleToggleExpand = () => {
    playSound('click');
    setIsExpanded(!isExpanded);
  };

  const handleShare = async () => {
    playSound('click');

    const impactParts: string[] = [];
    if (impacts.savings !== 0) impactParts.push(`💰 ${impacts.savings > 0 ? '+' : ''}₹${impacts.savings}`);
    if (impacts.debt !== 0) impactParts.push(`📉 Debt ${impacts.debt > 0 ? '+' : ''}₹${impacts.debt}`);
    if (impacts.happiness !== 0) impactParts.push(`🙂 ${impacts.happiness > 0 ? '+' : ''}${impacts.happiness}%`);
    if (impacts.health !== 0) impactParts.push(`❤️ ${impacts.health > 0 ? '+' : ''}${impacts.health}%`);
    if ((impacts.relationships || 0) !== 0) impactParts.push(`🤝 ${impacts.relationships > 0 ? '+' : ''}${impacts.relationships}%`);

    const shareText = `🇮🇳 Arth Mitra Update\n\n"${lastEvent.previous_outcome_title}"\n${lastEvent.previous_outcome_desc}\n\n${impactParts.join('  |  ')}\n\nCan you balance money and life?`;

    // Try Native Share
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Arth Mitra - My Financial Journey',
          text: shareText,
        });
      } catch (err) {
        console.log('Share dismissed');
      }
    } else {
      // Fallback to Clipboard
      try {
        await navigator.clipboard.writeText(shareText);
        setShowCopied(true);
        setTimeout(() => setShowCopied(false), 2500);
      } catch (err) {
        console.error('Failed to copy', err);
      }
    }
  };

  // Safe check for relationships since it might not exist in old events if not migrated
  const relImpact = impacts.relationships || 0;

  // Prepare grid items array for clean mapping and staggering
  const gridItems = [
    {
      id: 'savings',
      condition: impacts.savings !== 0,
      render: () => (
        <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/70 shadow-sm ${impacts.savings > 0 ? 'border-accent-green/50' : 'border-accent-red/50'}`}>
          <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('savings')}</span>
          <div className={`text-h3 font-bold flex items-center ${impacts.savings > 0 ? 'text-accent-green' : 'text-accent-red'}`}>
            <IndianRupee className="w-4 h-4 mr-1" />
            {impacts.savings > 0 ? '+' : ''}{impacts.savings}
          </div>
        </div>
      )
    },
    {
      id: 'happiness',
      condition: impacts.happiness !== 0,
      render: () => (
        <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/70 shadow-sm ${impacts.happiness > 0 ? 'border-accent-yellow/50' : 'border-neutral-soft/30'}`}>
          <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('happiness')}</span>
            <div className={`text-h3 font-bold flex items-center ${impacts.happiness > 0 ? 'text-accent-yellow' : 'text-neutral-soft'}`}>
            <Smile className="w-5 h-5 mr-1" />
            {impacts.happiness > 0 ? '+' : ''}{impacts.happiness}%
          </div>
        </div>
      )
    },
    {
      id: 'health',
      condition: impacts.health !== 0,
      render: () => (
        <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/70 shadow-sm ${impacts.health > 0 ? 'border-accent-pink/50' : 'border-accent-red/50'}`}>
          <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('health')}</span>
            <div className={`text-h3 font-bold flex items-center ${impacts.health > 0 ? 'text-accent-pink' : 'text-accent-red'}`}>
            <Heart className="w-5 h-5 mr-1" />
            {impacts.health > 0 ? '+' : ''}{impacts.health}%
          </div>
        </div>
      )
    },
    {
      id: 'relationships',
      condition: relImpact !== 0,
      render: () => (
        <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/70 shadow-sm ${relImpact > 0 ? 'border-accent-purple/50' : 'border-accent-red/50'}`}>
          <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('relationships')}</span>
            <div className={`text-h3 font-bold flex items-center ${relImpact > 0 ? 'text-accent-purple' : 'text-accent-red'}`}>
            <Users className="w-5 h-5 mr-1" />
            {relImpact > 0 ? '+' : ''}{relImpact}%
          </div>
        </div>
      )
    },
    {
      id: 'debt',
      condition: impacts.debt !== 0,
      render: () => (
        <div className={`p-4 rounded-card border flex flex-col items-center justify-center bg-white/70 shadow-sm ${impacts.debt < 0 ? 'border-accent-green/50' : 'border-accent-red/50'}`}>
          <span className="text-caption font-bold uppercase text-neutral-soft mb-1">{t('debt')}</span>
            <div className={`text-h3 font-bold flex items-center ${impacts.debt < 0 ? 'text-accent-green' : 'text-accent-red'}`}>
            {impacts.debt > 0 ? <TrendingUp className="w-5 h-5 mr-1" /> : <TrendingDown className="w-5 h-5 mr-1" />}
            {impacts.debt > 0 ? '+' : ''}{impacts.debt}
          </div>
        </div>
      )
    }
  ];

  const activeItems = gridItems.filter(i => i.condition);

  return (
    <div className="flex flex-col gap-6 justify-center w-full min-h-full">

      {/* Result Story Card - Pop In */}
      <div className="glass-card p-8 rounded-card text-center shadow-xl border-white/60 relative z-10 opacity-0 animate-pop-in">

        {/* Share Button (Top Right) */}
        <button 
           onClick={handleShare}
           className="absolute top-4 right-4 p-2.5 rounded-full bg-white/50 hover:bg-white text-brand/60 hover:text-brand transition-all shadow-sm active:scale-95 group"
           title={t('share_button')}
        >
           {showCopied ? (
             <div className="flex items-center gap-1.5">
               <Check size={16} className="text-accent-green" strokeWidth={3} />
               <span className="text-[10px] font-bold text-accent-green uppercase tracking-wide animate-fade-in">{t('copied')}</span>
             </div>
           ) : (
             <Share2 size={18} />
           )}
        </button>

        <div className="inline-block px-4 py-1.5 rounded-full bg-accent-yellow/20 text-brand text-caption font-bold tracking-wide uppercase mb-6">
          Result
        </div>
        <h2 className="text-h1 text-brand mb-4 leading-tight">
          {lastEvent.previous_outcome_title || "Done!"}
        </h2>
        <p className="text-body text-neutral-soft leading-relaxed mb-6">
          {lastEvent.previous_outcome_desc}
        </p>

        {/* Financial Flow Explanation */}
        {lastEvent.financial_explanation && (
           <button 
             onClick={handleToggleExpand}
             className="w-full bg-white/60 border border-white/80 rounded-2xl p-4 text-caption text-neutral-dark flex items-start gap-3 text-left shadow-sm hover:bg-white/80 transition-all duration-200 active:scale-[0.98] group cursor-pointer overflow-hidden"
             aria-expanded={isExpanded}
           >
              <Info className="w-5 h-5 text-brand shrink-0 mt-0.5" />
              <div className="flex-1 min-w-0">
                 <div 
                   className="transition-[max-height] duration-500 ease-in-out overflow-hidden"
                   style={{ maxHeight: isExpanded ? '500px' : '44px' }} // 44px approx 2 lines
                 >
                   <span className={`leading-snug block ${isExpanded ? '' : 'line-clamp-2'}`}>
                      {lastEvent.financial_explanation}
                   </span>
                 </div>
              </div>
              <ChevronDown 
                className={`w-4 h-4 text-neutral-soft/70 shrink-0 mt-1 transition-transform duration-500 ease-in-out ${isExpanded ? 'rotate-180' : ''}`} 
              />
           </button>
        )}
      </div>

      {/* Stat Changes Grid - Staggered Fade Up */}
      <div className="grid grid-cols-2 gap-4 w-full">
        {activeItems.map((item, index) => (
          <div 
            key={item.id} 
            className="opacity-0 animate-fade-in-up"
            style={{ animationDelay: `${200 + (index * 100)}ms` }}
          >
            {item.render()}
          </div>
        ))}
      </div>

      {/* Primary CTA Button - Sticky at bottom */}
      <div className="sticky bottom-0 pb-4 pt-4 -mb-4 bg-gradient-to-t from-[#f0fdf9] via-[#f0fdf9]/95 to-transparent z-20 mt-auto opacity-0 animate-fade-in" style={{ animationDelay: '600ms' }}>
        <button
          onClick={handleNextClick}
          className="w-full bg-brand text-white py-5 rounded-btn font-bold text-h3 shadow-btn hover:shadow-btn-hover hover:-translate-y-0.5 transition-all flex items-center justify-center group"
        >
          {t('next_turn')} <ArrowRight className="ml-2 w-6 h-6 group-hover:translate-x-1 transition-transform" />
        </button>
      </div>

      <div className="h-2" />
    </div>
  );
};

import React from 'react';
import { Wallet, Settings } from 'lucide-react';
import { Language } from '../types';
import { getTranslation } from '../translations';
import { playSound } from '../services/audioService';

interface HeaderProps {
  language: Language;
  onLanguageChange: (lang: Language) => void;
  onOpenSettings: () => void;
}

export const Header: React.FC<HeaderProps> = ({ language, onLanguageChange, onOpenSettings }) => {

  const languages: { code: Language; label: string }[] = [
    { code: 'en', label: 'En' },
    { code: 'hi', label: 'Hi' },
    { code: 'hinglish', label: 'Hng' },
  ];

  const handleSettingsClick = () => {
    playSound('click');
    onOpenSettings();
  };

  const handleLanguageClick = (lang: Language) => {
    if (lang !== language) {
       playSound('click');
       onLanguageChange(lang);
    }
  };

  return (
    <div className="w-full px-4 py-3 transition-all">
      <div className="max-w-[500px] mx-auto flex items-center justify-between">

        {/* Brand */}
        <div className="flex items-center gap-3">
          <div className="bg-brand p-2 rounded-xl shadow-btn shrink-0">
            <Wallet className="w-5 h-5 text-white" strokeWidth={2.5} />
          </div>
          <h1 className="text-h3 text-brand font-extrabold tracking-tight truncate hidden sm:block">
            {getTranslation(language, 'header_title')}
          </h1>
        </div>

        {/* Actions Group */}
        <div className="flex items-center gap-2 sm:gap-3">

            {/* Settings Button */}
            <button
                onClick={handleSettingsClick}
                className="w-9 h-9 rounded-full bg-neutral-glass border border-white/40 flex items-center justify-center text-neutral-soft hover:bg-brand hover:text-white transition-all shadow-sm active:scale-95"
                aria-label="Settings"
            >
                <Settings size={18} />
            </button>

            {/* Language Switcher */}
            <div className="flex p-1 rounded-full bg-neutral-glass border border-white/40 shrink-0">
              {languages.map((lang) => (
                <button
                  key={lang.code}
                  onClick={() => handleLanguageClick(lang.code)}
                  className={`
                    px-2 sm:px-3 py-1.5 rounded-full text-caption font-bold transition-all duration-200
                    ${language === lang.code 
                      ? 'bg-brand text-white shadow-sm' 
                      : 'text-neutral-soft hover:text-brand'}
                  `}
                >
                  {lang.label}
                </button>
              ))}
            </div>
        </div>
      </div>
    </div>
  );
};
